INDEX_HTML='<!doctype html>\n<html lang="id">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover">\n<title>FR Tool — Workspace</title>\n<link rel="manifest" href="/manifest.json">\n<meta name="theme-color" content="#faf9f5" id="meta-theme-color">\n<meta name="mobile-web-app-capable" content="yes">\n<meta name="apple-mobile-web-app-capable" content="yes">\n<meta name="apple-mobile-web-app-status-bar-style" content="black-translucent">\n<meta name="apple-mobile-web-app-title" content="FR Tool">\n<link rel="apple-touch-icon" href="/icon-192.png">\n<link rel="icon" type="image/png" sizes="192x192" href="/icon-192.png">\n<link rel="icon" type="image/png" sizes="512x512" href="/icon-512.png">\n<script>\n(function(){\n  try {\n    if (localStorage.getItem(\'frtool-theme\') === \'dark\') {\n      document.documentElement.setAttribute(\'data-theme\', \'dark\');\n      var m = document.querySelector(\'meta[name="theme-color"]\');\n      if (m) m.setAttribute(\'content\', \'#262624\');\n    }\n  } catch(e){}\n})();\n</script>\n<script src="https://cdn.jsdelivr.net/npm/gsap@3.12.5/dist/gsap.min.js"></script>\n<script src="https://unpkg.com/lucide@0.462.0/dist/umd/lucide.js"></script>\n<link rel="preconnect" href="https://fonts.googleapis.com">\n<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\n<link href="https://fonts.googleapis.com/css2?family=Poppins:wght@500;600;700&family=Lora:ital,wght@0,400;1,400&display=swap" rel="stylesheet">\n<style>\n  :root {\n    --bg-main: #faf9f5; --bg-panel: #f0ede5; --bg-hover: #e5dfd4; --border: #ccc5b9;\n    --text-main: #141413; --text-muted: #6b6356;\n    --accent: #d97757; --accent-hover: #c4623f;\n    --ok: #2e7d4f; --err: #c0392b; --warn: #b5850a;\n    --safe-b: env(safe-area-inset-bottom, 0px);\n    --safe-t: env(safe-area-inset-top, 0px);\n    --sidebar-w: 260px; --radius: 10px;\n    --restore-panel-h: min(68vh, 560px);\n  }\n  :root[data-theme="dark"] {\n    --bg-main: #262624; --bg-panel: #30302e; --bg-hover: #3a3936; --border: #46443f;\n    --text-main: #f2f0e9; --text-muted: #a8a29a;\n    --accent: #d97757; --accent-hover: #e0895f;\n    --ok: #4caf7d; --err: #e5534b; --warn: #d9a441;\n  }\n  html, body, .sidebar, .top-header, .main-content, .github-box, #modal {\n    transition: background-color .2s ease, border-color .2s ease, color .2s ease;\n  }\n  * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; font-family: \'Lora\', Georgia, serif; }\n  html, body { height: 100%; margin: 0; background: var(--bg-main); color: var(--text-main); overflow: hidden; }\n  button, input, select, textarea, .btn, .nav-btn, .nav-section, .sidebar-header,\n  h1, h2, h3, .repo-summary-lbl, .box-header, .status-pill, .log-toolbar, .sheet-title, .sheet-opts,\n  .restore-mode-btn, .branch-badge, label { font-family: \'Poppins\', -apple-system, BlinkMacSystemFont, sans-serif; }\n  \n  /* Layout App */\n  #app { display: flex; height: 100dvh; width: 100vw; position: relative; }\n  \n  /* Sidebar */\n  .sidebar {\n    width: var(--sidebar-w); background: var(--bg-panel); border-right: 1px solid var(--border);\n    display: flex; flex-direction: column; z-index: 40; transition: transform 0.3s ease;\n  }\n  .sidebar-header {\n    height: 60px; padding: 0 20px; display: flex; align-items: center; gap: 10px;\n    border-bottom: 1px solid var(--border); font-weight: 600; font-size: 16px; color: var(--text-main);\n  }\n  .sidebar-header svg { color: var(--accent); width: 22px; height: 22px; }\n  .sidebar-header .theme-toggle {\n    margin-left: auto; background: transparent; border: 1px solid var(--border); border-radius: 7px;\n    width: 30px; height: 30px; display: flex; align-items: center; justify-content: center;\n    cursor: pointer; color: var(--text-muted); flex-shrink: 0;\n  }\n  .sidebar-header .theme-toggle:hover { background: var(--bg-hover); color: var(--text-main); }\n  .sidebar-header .theme-toggle svg { width: 15px; height: 15px; color: inherit; }\n  .theme-icon-dark { display: none; }\n  [data-theme="dark"] .theme-icon-light { display: none; }\n  [data-theme="dark"] .theme-icon-dark { display: inline-flex; }\n  .sidebar-nav { flex: 1; overflow-y: auto; padding: 15px 10px; display: flex; flex-direction: column; gap: 4px; }\n  .nav-section {\n    font-size: 11px; font-weight: 600; color: var(--text-muted); margin: 15px 0 5px 10px; letter-spacing: 0.5px;\n  }\n  .nav-btn {\n    background: transparent; border: none; color: var(--text-main); text-align: left;\n    padding: 10px 12px; border-radius: var(--radius); font-size: 14px; cursor: pointer;\n    display: flex; align-items: center; gap: 10px; transition: background 0.15s;\n  }\n  .nav-btn:hover { background: var(--bg-hover); }\n  .nav-btn.active { background: rgba(217, 119, 87, 0.12); color: var(--accent); font-weight: 500; }\n  .nav-btn svg { width: 16px; height: 16px; flex-shrink: 0; opacity: 0.8; }\n  .nav-btn.active svg { opacity: 1; }\n\n  /* Mobile Overlay */\n  .sidebar-overlay {\n    position: fixed; inset: 0; background: rgba(0,0,0,0.6); z-index: 39; display: none; opacity: 0; transition: opacity 0.3s;\n  }\n\n  @media (max-width: 768px) {\n    .sidebar { position: fixed; left: 0; top: 0; bottom: 0; transform: translateX(-100%); }\n    .sidebar.open { transform: translateX(0); }\n    .sidebar-overlay.open { display: block; opacity: 1; }\n  }\n\n  /* Main Workspace */\n  .main-content { flex: 1; display: flex; flex-direction: column; min-width: 0; }\n  \n  .top-header {\n    height: 60px; padding: 0 20px; border-bottom: 1px solid var(--border);\n    display: flex; align-items: center; justify-content: space-between; background: var(--bg-main);\n  }\n  .header-left { display: flex; align-items: center; gap: 12px; min-width: 0; }\n  .menu-toggle {\n    display: none; background: transparent; border: 1px solid var(--border); border-radius: 6px;\n    color: var(--text-main); padding: 6px; cursor: pointer;\n  }\n  @media (max-width: 768px) { .menu-toggle { display: flex; align-items: center; justify-content: center; } }\n  .repo-info { display: flex; align-items: center; gap: 8px; font-size: 14px; font-weight: 500; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;}\n  .repo-info svg { width: 18px; height: 18px; color: var(--text-muted); }\n  .branch-badge {\n    background: rgba(217, 119, 87, 0.12); color: var(--accent); padding: 4px 8px;\n    border-radius: 99px; font-size: 12px; display: inline-flex; align-items: center; gap: 4px;\n  }\n  .branch-badge svg { width: 14px; height: 14px; color: var(--accent); }\n\n  .status-pill {\n    display: flex; align-items: center; gap: 6px; font-size: 12px; font-weight: 500;\n    padding: 6px 12px; border-radius: 99px; background: var(--bg-panel); border: 1px solid var(--border);\n  }\n  .status-pill .dot { width: 8px; height: 8px; border-radius: 50%; background: var(--text-muted); }\n  .status-pill.running .dot { background: var(--accent); animation: blink 1s infinite; }\n  .status-pill.waiting .dot { background: var(--warn); animation: blink 1s infinite; }\n  .status-pill.done .dot { background: var(--ok); }\n  .status-pill.error .dot { background: var(--err); }\n  @keyframes blink { 0%,100%{opacity:1;} 50%{opacity:0.4;} }\n\n  /* Views */\n  .view-container { flex: 1; position: relative; overflow: hidden; }\n.view { position: absolute; inset: 0; display: none; flex-direction: column; overflow-y: auto; padding: 20px; padding-bottom: 80px; }\n.view.active { display: flex; }\n@media (max-width: 768px) { .view { padding: 14px 10px; padding-bottom: 80px; } }\n} }\n\n  /* GitHub Style Repo View */\n  .repo-summary {\n    display: flex; align-items: stretch; background: var(--bg-panel); border: 1px solid var(--border);\n    border-radius: 10px; margin-bottom: 18px; flex-shrink: 0; overflow: hidden;\n  }\n  .repo-summary-item { display: flex; align-items: center; gap: 12px; padding: 16px 20px; flex: 1; min-width: 0; }\n  .repo-summary-clickable { cursor: pointer; transition: background 0.15s; }\n  .repo-summary-clickable:hover, .repo-summary-clickable:focus-visible { background: var(--bg-hover); outline: none; }\n  .repo-summary-icon {\n    width: 36px; height: 36px; border-radius: 8px; background: rgba(217, 119, 87, 0.12); color: var(--accent);\n    display: flex; align-items: center; justify-content: center; flex-shrink: 0;\n  }\n  .repo-summary-icon svg { width: 17px; height: 17px; }\n  .repo-summary-text { min-width: 0; }\n  .repo-summary-val { font-size: 20px; font-weight: 600; color: var(--text-main); line-height: 1.25; }\n  .repo-summary-val-msg { font-size: 14px; font-weight: 500; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n  .repo-summary-lbl { font-size: 11px; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; margin-top: 2px; }\n  .repo-summary-divider { width: 1px; background: var(--border); flex-shrink: 0; margin: 12px 0; }\n  @media (max-width: 560px) {\n    .repo-summary { flex-direction: column; }\n    .repo-summary-divider { width: auto; height: 1px; margin: 0 20px; }\n  }\n  .repo-readme-body { padding:16px 18px; font-family: ui-monospace, monospace; font-size:12.5px; line-height:1.6; color: var(--text-main); white-space: pre-wrap; word-break: break-word; max-height: 320px; overflow-y: auto; }\n  .repo-readme-truncated { padding: 8px 18px 14px; font-size: 12px; color: var(--text-muted); border-top: 1px dashed var(--border); }\n  .file-row.repo-row .file-name { flex: none; }\n  .file-main { flex: 1; min-width: 0; display: flex; flex-direction: column; gap: 2px; }\n  .file-meta { font-size: 12px; color: var(--text-muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; display:flex; align-items:center; gap:5px; }\n  .file-meta svg { width: 11px; height: 11px; flex-shrink: 0; opacity: 0.8; }\n  .file-size-badge { color: var(--text-muted); font-size: 11px; font-weight: 500; flex-shrink: 0; margin-left: 8px; }\n  \n  .github-box { border: 1px solid var(--border); border-radius: 6px; background: var(--bg-main); overflow: hidden; flex-shrink: 0; }\n  .box-header {\n    background: var(--bg-panel); padding: 12px 16px; border-bottom: 1px solid var(--border);\n    display: flex; justify-content: space-between; align-items: center; font-weight: 500; font-size: 14px;\n  }\n  .box-header .ghost-btn { background: transparent; border: none; color: var(--text-muted); cursor: pointer; padding: 4px; border-radius: 4px; }\n  .box-header .ghost-btn:hover { background: var(--bg-hover); color: var(--text-main); }\n  \n  .file-row {\n    display: flex; align-items: center; padding: 10px 16px; border-bottom: 1px solid var(--border);\n    font-size: 14px; gap: 15px; cursor: pointer; transition: background 0.15s;\n  }\n  .file-row:last-child { border-bottom: none; }\n  .file-row:hover { background: var(--bg-hover); }\n  .file-row.stale { background: rgba(181,133,10,0.08); border-left: 3px solid var(--warn); padding-left: 13px; }\n  .file-row.stale:hover { background: rgba(181,133,10,0.16); }\n  .file-row.stale .file-name { font-style: italic; opacity: 0.8; }\n  .file-icon { width: 20px; display: flex; justify-content: center; color: var(--text-muted); }\n  .file-icon svg { width: 16px; height: 16px; }\n  .file-icon.folder svg { color: #1565c0; fill: rgba(21, 101, 192, 0.12); }\n  .file-name { flex: 1; color: var(--text-main); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n  .file-date { color: var(--text-muted); font-size: 13px; text-align: right; min-width: 120px; }\n  @media (max-width: 600px) { .file-date { display: none; } }\n\n   /* ── Patch Panel ── */\n   .patch-container {\n     display: flex; flex-direction: column; gap: 12px;\n     flex: 1; width: 100%; max-width: 860px; margin: 0 auto; min-height: 0;\n     transition: max-width 0.5s cubic-bezier(0.16, 1, 0.3, 1);\n   }\n   .patch-container.log-active { max-width: 1400px; }\n   /* Segmented tab bar */\n   .patch-tab-bar {\n     display: flex; gap: 3px;\n     background: #0d1117; border: 1px solid #21262d;\n     border-radius: 10px; padding: 4px; flex-shrink: 0;\n   }\n   .patch-tab {\n     flex: 1; padding: 8px 14px; border: none; background: transparent;\n     color: #8b949e; border-radius: 7px; cursor: pointer; font-size: 13px;\n     font-weight: 500; display: flex; align-items: center; justify-content: center;\n     gap: 7px; transition: color 0.18s; position: relative;\n   }\n   .patch-tab.active {\n     background: #161b22; color: #e6edf3;\n     box-shadow: 0 1px 4px rgba(0,0,0,0.35);\n   }\n   .patch-tab svg { width: 14px; height: 14px; }\n   /* Running indicator dot on Log tab */\n   .tab-run-dot {\n     width: 7px; height: 7px; border-radius: 50%;\n     background: #f85149; display: none; flex-shrink: 0;\n     box-shadow: 0 0 6px #f85149;\n     animation: dotPulse 1.2s ease-in-out infinite;\n   }\n   .tab-run-dot.show { display: inline-block; }\n   @keyframes dotPulse { 0%,100%{opacity:1} 50%{opacity:0.35} }\n\n   /* Editor area — textarea native murni, TANPA overlay <pre> terpisah.\n      Sengaja dibongkar dari teknik "textarea transparan + pre warna di\n      belakangnya": dua elemen DOM terpisah yg harus selalu sinkron posisi\n      teksnya itu rapuh dari akarnya (font metric, white-space, scroll,\n      semua bisa geser lagi kapan pun). Textarea native = browser sendiri\n      yang pegang penuh render teks & kursor -> presisi 100% terjamin\n      selamanya, gak ada lagi kemungkinan drift. Trade-off: warna syntax\n      per-token (:find/:replace/dst) dilepas, teks jadi satu warna polos. */\n   .patch-editor-wrap {\n     flex: 1; border: 1px solid #21262d;\n     border-radius: 8px; background: #0d1117; overflow: hidden; min-height: 260px;\n   }\n   .patch-input {\n     display: block; width: 100%; height: 100%; padding: 14px 16px;\n     font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\n     font-size: 13px; line-height: 1.6; white-space: pre-wrap; overflow: auto;\n     border: none; margin: 0; background: transparent; color: #e6edf3;\n     caret-color: #d97757; resize: none; outline: none;\n   }\n\n   .patch-actions {\n     display: flex; gap: 8px; flex-shrink: 0;\n   }\n  .btn {\n    background: var(--bg-panel); border: 1px solid var(--border); color: var(--text-main);\n    padding: 8px 16px; border-radius: 6px; font-size: 14px; font-weight: 500; cursor: pointer;\n    display: inline-flex; align-items: center; gap: 6px; transition: all 0.2s;\n  }\n  .btn:hover { background: var(--bg-hover); border-color: #8b949e; }\n  .btn-primary { background: var(--ok); color: #fff; border-color: rgba(0,0,0,0.08); }\n  .btn-primary:hover { background: #236040; border-color: rgba(0,0,0,0.08); }\n  .btn-accent { background: var(--accent); color: #fff; border-color: rgba(0,0,0,0.08); }\n  .btn-accent:hover { background: var(--accent-hover); }\n\n  /* Terminal Log View */\n  .log-toolbar { display: flex; justify-content: space-between; align-items: center; padding-bottom: 10px; }\n\n  .log-actions { display: flex; gap: 8px; }\n   /* Log Panel — inline, sepanel dgn Edit (bukan overlay layar penuh lagi) */\n   #log-fullscreen {\n     display: none; flex: 1; flex-direction: column; position: relative;\n     border: 1px solid #21262d; border-radius: 8px; background: #0d1117;\n     overflow: hidden; min-height: 260px; touch-action: pan-y;\n     font-family: ui-monospace, SFMono-Regular, monospace;\n   }\n   #log-fullscreen.open { display: flex; }\n   /* Indikator persen zoom — muncul sekejap saat pinch dua jari */\n   .log-zoom-indicator {\n     position: absolute; top: 10px; right: 14px; z-index: 2;\n     background: rgba(22,27,34,0.92); border: 1px solid #30363d; color: #e6edf3;\n     font-size: 11px; font-family: ui-monospace, monospace; padding: 3px 10px;\n     border-radius: 99px; opacity: 0; pointer-events: none;\n     transition: opacity 0.2s ease;\n   }\n   .log-zoom-indicator.show { opacity: 1; }\n   /* Icon buttons */\n   .log-icon-btn {\n     background: transparent; border: none; color: #3d444d;\n     padding: 5px 6px; border-radius: 5px; cursor: pointer;\n     display: flex; align-items: center; transition: all 0.14s;\n   }\n   .log-icon-btn:hover { background: #161b22; color: #8b949e; }\n   .log-icon-btn.danger:hover { color: #f85149; }\n   .log-icon-btn.on { color: #3fb950; }\n   /* Baris aksi log — pengganti header lama, posisinya sejajar dgn .patch-actions */\n   .log-actions-row {\n     display: none; justify-content: flex-end; align-items: center; gap: 6px;\n     background: #0d1117; border: 1px solid #21262d; border-radius: 8px;\n     padding: 7px 9px; flex-shrink: 0;\n   }\n   .log-actions-row.open { display: flex; }\n   #log {\n     flex: 1; overflow-y: auto; background: #0d1117; min-height: 0;\n     padding: 18px 22px; font-family: ui-monospace, SFMono-Regular, monospace;\n     font-size: calc(13px * var(--log-scale, 0.85)); white-space: pre-wrap;\n     line-height: 1.65; color: #e6edf3;\n   }\n   .term-row { min-height: 1.5em; }\n   /* Baris diff bernomor (preview patch) — teks yg lanjut/wrap sejajar ke kode, bukan nempel ke kolom nomor */\n   .diff-gutter-row {\n     padding-left: calc(var(--gutter-ch, 0) * 1ch);\n     text-indent: calc(var(--gutter-ch, 0) * -1ch);\n   }\n   /* Inline prompt card di dalam log gelap */\n   #log .inline-prompt-card { background: #21262d; border-color: var(--accent); }\n   #log .inline-prompt-card .inline-prompt-text { color: #c9d1d9; }\n   #log .inline-prompt-card.answered { border-color: #2e7d4f; }\n\n  /* Modals (Sheet) */\n   .modal-overlay {\n     position: fixed; inset: 0; background: rgba(0,0,0,0.7); z-index: 600;\n     display: none; align-items: center; justify-content: center; padding: 20px;\n     backdrop-filter: blur(3px);\n   }\n  .modal-overlay.open { display: flex; }\n  #modal {\n    background: var(--bg-panel); border: 1px solid var(--border); border-radius: 12px;\n    width: 100%; max-width: 450px; max-height: 85vh; display: flex; flex-direction: column;\n    box-shadow: 0 24px 48px rgba(0,0,0,0.5);\n  }\n  .sheet-header { padding: 16px 20px; border-bottom: 1px solid var(--border); display: flex; justify-content: space-between; align-items: center; }\n  .sheet-title { font-weight: 600; display: flex; align-items: center; gap: 8px; color: var(--text-main); }\n  .sheet-title svg { color: var(--accent); }\n  .sheet-body { padding: 20px; overflow-y: auto; font-size: 14px; line-height: 1.5; }\n  .sheet-body input[type=text], .sheet-body textarea {\n    width: 100%; background: var(--bg-main); border: 1px solid var(--border); color: var(--text-main);\n    padding: 10px 12px; border-radius: 6px; margin-top: 10px; font-family: inherit; font-size: 14px;\n  }\n  .sheet-body textarea { min-height: 120px; font-family: monospace; }\n  .sheet-opts { display: flex; flex-direction: column; gap: 8px; margin-top: 20px; }\n  .sheet-opts button { justify-content: center; padding: 10px; }\n\n  /* Image Lightbox — preview gambar ala GitHub */\n  .img-lightbox-overlay {\n    position: fixed; inset: 0; background: rgba(0,0,0,0.85); z-index: 700;\n    display: none; flex-direction: column; padding: 16px;\n  }\n  .img-lightbox-overlay.open { display: flex; }\n  .img-lightbox-header { display: flex; align-items: center; justify-content: space-between; gap: 12px; color: #f2f0e9; font-size: 14px; font-weight: 500; padding-bottom: 12px; flex-shrink: 0; }\n  .img-lightbox-header .ghost-btn { background: transparent; border: none; color: #f2f0e9; cursor: pointer; padding: 6px; border-radius: 6px; display:flex; }\n  .img-lightbox-header .ghost-btn:hover { background: rgba(255,255,255,0.14); }\n  .img-lightbox-body { flex: 1; min-height: 0; display: flex; align-items: center; justify-content: center; overflow: auto; }\n  .img-lightbox-body img {\n    max-width: 100%; max-height: 100%; border-radius: 6px; box-shadow: 0 8px 32px rgba(0,0,0,0.5);\n    background: repeating-conic-gradient(#3a3936 0% 25%, #2a2a28 0% 50%) 50% / 20px 20px;\n  }\n\n  /* Inline Prompt Card — khusus kind \'anykey\'. Tampil menyatu di terminal log\n     (gaya GitHub device-flow), BUKAN modal yang tiba-tiba nutup layar. */\n  .inline-prompt-card {\n    display: flex; align-items: center; gap: 14px; margin: 10px 0; padding: 14px 16px;\n    background: var(--bg-panel); border: 1px solid var(--accent); border-radius: 8px;\n    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; font-size: 14px;\n  }\n  .inline-prompt-card .inline-prompt-icon { color: var(--accent); flex-shrink: 0; display: flex; }\n  .inline-prompt-card .inline-prompt-icon svg { width: 20px; height: 20px; }\n  .inline-prompt-card .inline-prompt-text { flex: 1; color: var(--text-main); line-height: 1.4; }\n  .inline-prompt-card.answered { border-color: var(--ok); opacity: 0.75; }\n  .inline-prompt-card.answered .inline-prompt-icon { color: var(--ok); }\n  .inline-prompt-card button { flex-shrink: 0; }\n\n   /* folder input hidden — kept for JS compatibility */\n\n  /* Log specific styling */\n  .log-error-block { background: rgba(248, 81, 73, 0.1); border: 1px solid rgba(248, 81, 73, 0.4); color: #ff7b72; padding: 10px; border-radius: 6px; margin: 8px 0; }\n  .log-badge { display: inline-flex; align-items: center; gap: 4px; padding: 2px 8px; border-radius: 99px; font-size: 11px; font-weight: 600; margin-right: 8px; }\n  .log-badge.ok { background: rgba(46, 125, 79, 0.15); color: #2e7d4f; }\n  .log-badge.err { background: rgba(192, 57, 43, 0.15); color: #c0392b; }\n  .log-badge.skip { background: rgba(181, 133, 10, 0.15); color: #b5850a; }\n\n  /* Restore Session */\n  .restore-mode-toggle { display:flex; gap:6px; background:var(--bg-panel); border:1px solid var(--border); border-radius:8px; padding:3px; }\n  .restore-mode-btn { background:transparent; border:none; color:var(--text-muted); padding:6px 12px; border-radius:6px; font-size:13px; font-weight:500; cursor:pointer; display:flex; align-items:center; gap:6px; }\n  .restore-mode-btn.active { background:var(--accent); color:#fff; }\n  .restore-mode-btn svg { width:14px; height:14px; }\n  .restore-breadcrumb { padding:8px 16px; font-family:monospace; font-size:12px; color:var(--text-muted); border-bottom:1px solid var(--border); }\n  .restore-pager { display:flex; align-items:center; justify-content:center; flex-wrap:wrap; gap:6px; padding:14px 6px 4px; }\n  .restore-page-btn { min-width:34px; height:34px; padding:0 8px; background:var(--bg-panel); border:1px solid var(--border); color:var(--text-main); border-radius:8px; font-size:13px; font-weight:500; cursor:pointer; display:inline-flex; align-items:center; justify-content:center; }\n  .restore-page-btn svg { width:15px; height:15px; }\n  .restore-page-btn:hover:not(:disabled) { background:var(--bg-hover); }\n  .restore-page-btn.active { background:var(--accent); border-color:var(--accent); color:#fff; }\n  .restore-page-btn:disabled { opacity:0.35; cursor:default; }\n  .restore-page-dots { color:var(--text-muted); padding:0 2px; }\n  .restore-page-info { width:100%; text-align:center; font-size:12px; color:var(--text-muted); margin-top:4px; }\n  \n  #restore-list { border-radius: 0 0 6px 6px; }\n  \n  #restore-back-btn { padding:6px 8px; }\n   /* ── Diff Preview — GitHub Dark Style ──────────────────────────────────── */\n   .diff-warn { display:flex; align-items:center; gap:8px; background:rgba(210,153,34,0.12); border:1px solid rgba(210,153,34,0.35); color:#d29922; padding:10px 14px; border-radius:8px; font-size:13px; margin-top:12px; }\n   .diff-warn svg { width:16px; height:16px; flex-shrink:0; }\n   .diff-file { border:1px solid #30363d; border-radius:8px; overflow:hidden; margin-top:14px; background:#0d1117; box-shadow:0 4px 16px rgba(0,0,0,0.25); }\n   .diff-file-header { display:flex; justify-content:space-between; align-items:center; padding:10px 16px; background:#161b22; border-bottom:1px solid #30363d; font-size:13px; font-weight:500; gap:10px; flex-wrap:wrap; color:#e6edf3; }\n   .diff-file-name { font-family:ui-monospace,SFMono-Regular,monospace; color:#79c0ff; font-weight:600; display:flex; align-items:center; gap:6px; }\n   .diff-stat-badge { display:inline-flex; align-items:center; gap:8px; }\n   .diff-stat-plus { color:#3fb950; font-weight:700; font-size:13px; }\n   .diff-stat-minus { color:#f85149; font-weight:700; font-size:13px; }\n   .diff-stat-bar { display:inline-flex; width:60px; height:8px; border-radius:3px; overflow:hidden; background:#30363d; }\n   .diff-stat-bar .plus { background:#238636; }\n   .diff-stat-bar .minus { background:#da3633; }\n   /* ── Diff table: horizontal scroll, no line wrapping ── */\n   /* diff-zoom: controlled via --diff-zoom CSS var on :root */\n   .diff-table { font-family: ui-monospace, SFMono-Regular, \'Cascadia Code\', monospace; font-size: calc(12.5px * var(--diff-zoom, 1)); overflow-x:auto; overflow-y:auto; max-height: var(--restore-panel-h); display:block; width:100%; touch-action: pan-x pan-y; }\n   /* Indikator persen zoom diff — muncul sekejap saat pinch dua jari di panel preview */\n   .diff-zoom-indicator {\n     position: fixed; top: calc(var(--safe-t) + 70px); right: 16px; z-index: 200;\n     background: rgba(22,27,34,0.92); border: 1px solid #30363d; color: #e6edf3;\n     font-size: 12px; font-family: ui-monospace, monospace; padding: 4px 12px;\n     border-radius: 99px; opacity: 0; pointer-events: none;\n     transition: opacity 0.2s ease;\n   }\n   .diff-zoom-indicator.show { opacity: 1; }\n   .diff-row { display:flex; white-space:nowrap; line-height:1.75; min-width:fit-content; transition:background 0.08s; }\n   .diff-row:hover { filter:brightness(1.12); }\n   /* Row backgrounds — vivid enough to read on OLED dark */\n   .diff-row.ctx { background:#0d1117; }\n   .diff-row.add { background:rgba(35,134,54,0.28); border-left:3px solid #238636; }\n   .diff-row.del { background:rgba(218,54,51,0.28); border-left:3px solid #da3633; }\n   /* Dual gutter */\n   .diff-gutter-old {\n     min-width:38px; max-width:38px; text-align:right; padding:0 6px;\n     color:#484f58; user-select:none; flex-shrink:0;\n     border-right:1px solid #21262d; background:rgba(0,0,0,0.22);\n     font-size:11px; display:flex; align-items:center; justify-content:flex-end;\n   }\n   .diff-gutter-new {\n     min-width:38px; max-width:38px; text-align:right; padding:0 6px;\n     color:#484f58; user-select:none; flex-shrink:0;\n     border-right:1px solid #21262d; background:rgba(0,0,0,0.12);\n     font-size:11px; display:flex; align-items:center; justify-content:flex-end;\n   }\n   .diff-row.add .diff-gutter-new { color:#3fb950; font-weight:700; background:rgba(35,134,54,0.30); }\n   .diff-row.del .diff-gutter-old { color:#f85149; font-weight:700; background:rgba(218,54,51,0.30); }\n   .diff-row.ctx .diff-gutter-old,\n   .diff-row.ctx .diff-gutter-new { color:#3d444d; }\n   .diff-sym {\n     width:18px; min-width:18px; text-align:center; flex-shrink:0; font-weight:700;\n     font-size:13px; display:flex; align-items:center; justify-content:center;\n     border-right:1px solid #21262d;\n   }\n   .diff-row.add .diff-sym { color:#3fb950; background:rgba(35,134,54,0.30); }\n   .diff-row.del .diff-sym { color:#f85149; background:rgba(218,54,51,0.30); }\n   .diff-row.ctx .diff-sym { color:#3d444d; }\n   /* Code cell: pre (no wrap) — parent handles scroll */\n   .diff-code { white-space:pre; flex:1; padding:0 14px; color:#e6edf3; min-width:0; }\n   .diff-row.ctx .diff-code { color:#768390; }\n   /* Inline char highlights — more saturated than row bg */\n   .diff-chg-add { background:rgba(46,160,67,0.55); border-radius:2px; padding:0 1px; }\n   .diff-chg-del { background:rgba(218,54,51,0.55); border-radius:2px; padding:0 1px; text-decoration:line-through; text-decoration-color:rgba(248,81,73,0.7); }\n   .diff-ws { text-decoration:underline wavy #f85149; opacity:0.85; }\n   /* Separator @@ ... @@ */\n   .diff-sep { display:flex; align-items:stretch; background:#161b22; border-top:1px solid #21262d; border-bottom:1px solid #21262d; min-width:fit-content; }\n   .diff-sep-gutter { min-width:76px; max-width:76px; border-right:1px solid #21262d; background:rgba(0,0,0,0.18); display:flex; align-items:center; justify-content:center; color:#484f58; font-size:11px; padding:3px 0; }\n   .diff-sep-sym { width:18px; min-width:18px; border-right:1px solid #21262d; display:flex; align-items:center; justify-content:center; }\n   .diff-sep-body { padding:3px 12px; color:#388bfd; font-family:ui-monospace,monospace; font-size:12px; font-style:italic; }\n   /* Syntax — GitHub Dark palette */\n   .diff-cat-kw{color:#ff7b72} .diff-cat-str{color:#a5d6ff} .diff-cat-num{color:#79c0ff} .diff-cat-cmt{color:#8b949e;font-style:italic}\n   .diff-cat-deco{color:#ffa657} .diff-cat-func{color:#d2a8ff} .diff-cat-cls{color:#ffa657} .diff-cat-blt{color:#79c0ff}\n   .diff-cat-tag{color:#7ee787} .diff-cat-attr{color:#79c0ff} .diff-cat-sel{color:#ff7b72} .diff-cat-prop{color:#7ee787}\n  .restore-toast { position:fixed; bottom:24px; left:50%; transform:translateX(-50%) translateY(20px); background:var(--bg-panel); border:1px solid var(--border); color:var(--text-main); padding:12px 20px; border-radius:8px; font-size:14px; box-shadow:0 8px 24px rgba(0,0,0,0.4); z-index:200; opacity:0; transition:all 0.25s; max-width:90vw; }\n  .restore-toast.show { opacity:1; transform:translateX(-50%) translateY(0); }\n  .restore-toast.ok { border-color:var(--ok); }\n  .restore-toast.err { border-color:var(--err); color:var(--err); }\n</style>\n</head>\n<body>\n\n<div id="app">\n  <div class="sidebar-overlay" id="sidebar-overlay"></div>\n  <aside class="sidebar" id="sidebar">\n    <div class="sidebar-header">\n      <i data-lucide="github"></i> Workspace\n      <button class="theme-toggle" id="theme-toggle" type="button" title="Ganti tema terang/gelap" aria-label="Ganti tema terang/gelap">\n        <i data-lucide="sun" class="theme-icon-light"></i>\n        <i data-lucide="moon" class="theme-icon-dark"></i>\n      </button>\n    </div>\n    <nav class="sidebar-nav">\n      <div class="nav-section">WORKSPACE</div>\n      <button class="nav-btn active" data-view="repo"><i data-lucide="folder-code"></i> Repository</button>\n      <button class="nav-btn" data-view="patch"><i data-lucide="zap"></i> Patch Engine</button>\n      <button class="nav-btn" data-view="restore"><i data-lucide="history"></i> Pulihkan Sesi</button>\n\n\n      <div class="nav-section">OPERASI CORE</div>\n      <button class="nav-btn" data-view="cari-ganti"><i data-lucide="search-code"></i> Cari &amp; Ganti Manual</button>\n      <button class="nav-btn" data-view="checksyntax"><i data-lucide="shield-check"></i> Cek Sintaks</button>\n\n      <div class="nav-section">PENGATURAN</div>\n      <button class="nav-btn" data-view="ubah-dir"><i data-lucide="folder-open"></i> Ubah Direktori</button>\n      <button class="nav-btn" data-view="ai-setup"><i data-lucide="bot"></i> Setup AI Auto-Fix</button>\n      <button class="nav-btn" data-view="git-id"><i data-lucide="user-cog"></i> Identitas Git</button>\n      <button class="nav-btn" data-view="threshold"><i data-lucide="sliders-horizontal"></i> Threshold Matching</button>\n      <button class="nav-btn" data-view="promptai"><i data-lucide="copy"></i> Salin Prompt AI</button>\n    </nav>\n  </aside>\n\n  <main class="main-content">\n    <header class="top-header">\n      <div class="header-left">\n        <button class="menu-toggle" id="menu-toggle"><i data-lucide="menu"></i></button>\n        <div class="repo-info">\n          <i data-lucide="book-open"></i> <span id="header-repo-name">Memuat...</span>\n          <span class="branch-badge" id="header-branch-badge" style="display:none"><i data-lucide="git-branch"></i> <span id="header-branch">main</span></span>\n        </div>\n      </div>\n      <div class="status-pill idle" id="status-pill">\n         <span class="dot"></span><span id="status-pill-text">Idle</span>\n      </div>\n    </header>\n\n    <div class="view-container">\n      <!-- VIEW: REPOSITORY -->\n         <div id="view-repo" class="view active" style="flex-direction:column;">\n         <div class="repo-summary">\n           <div class="repo-summary-item repo-summary-clickable" id="stat-commits-card" onclick="openRestoreCommitsList()" role="button" tabindex="0" title="Lihat semua commit">\n             <div class="repo-summary-icon"><i data-lucide="git-commit"></i></div>\n             <div class="repo-summary-text">\n               <div class="repo-summary-val" id="stat-commits">0</div>\n               <div class="repo-summary-lbl">Total Commits</div>\n             </div>\n           </div>\n           <div class="repo-summary-divider"></div>\n           <div class="repo-summary-item repo-summary-clickable" id="stat-latest-commit-card" style="flex:2; min-width:0;" onclick="openLatestCommitDiff()" role="button" tabindex="0" title="Lihat diff commit terakhir">\n             <div class="repo-summary-icon"><i data-lucide="message-square"></i></div>\n             <div class="repo-summary-text" style="min-width:0;">\n               <div class="repo-summary-val repo-summary-val-msg" id="stat-latest-commit">-</div>\n               <div class="repo-summary-lbl">Latest Commit</div>\n             </div>\n           </div>\n         </div>\n\n         <div class="github-box" style="flex-shrink:0;">\n            <div class="box-header">\n               <span id="current-path-wrap" style="display:flex; align-items:center; gap:6px; min-width:0; overflow-x:auto; white-space:nowrap;">\n                 <i data-lucide="folder" style="width:14px; flex-shrink:0; color:var(--accent);"></i>\n                 <span id="current-path" style="font-family: monospace; color: var(--accent);">/</span>\n               </span>\n               <button id="btn-change-dir" class="ghost-btn" title="Ubah Direktori"><i data-lucide="folder-open"></i></button>\n            </div>\n            <div class="box-body" id="repo-file-list">\n               <div style="padding:20px; text-align:center; color:var(--text-muted)">Memuat struktur direktori...</div>\n            </div>\n         </div>\n\n         <div class="github-box" id="repo-readme-box" style="display:none; margin-top:15px; flex-shrink:0;"></div>\n       </div>\n\n      <!-- VIEW: PATCH ENGINE -->\n       <div id="view-patch" class="view">\n         <div class="patch-container">\n\n           <!-- Tab bar: Edit ↔ Log -->\n           <div class="patch-tab-bar">\n             <button class="patch-tab active" id="tab-editor">\n               <i data-lucide="code-2"></i> Edit\n             </button>\n             <button class="patch-tab" id="tab-log">\n               <i data-lucide="terminal"></i> Log\n               <span class="tab-run-dot" id="tab-run-dot"></span>\n             </button>\n           </div>\n\n           <!-- hidden folder (JS compat) -->\n           <input type="text" id="folder" style="display:none">\n\n           <!-- Editor -->\n           <div class="patch-editor-wrap">\n             <textarea id="patch" class="patch-input" placeholder=":title Judul patch&#10;:file path/ke/file.py&#10;:find&#10;kode lama&#10;:end_find&#10;:replace&#10;kode baru&#10;:end_replace" spellcheck="false"></textarea>\n           </div>\n\n           <!-- Action row -->\n           <div class="patch-actions" id="patch-editor-actions">\n             <button id="btn-apply" class="btn btn-primary" style="flex:1;justify-content:center;padding:11px;font-size:13.5px;">\n               <i data-lucide="play"></i> Terapkan\n             </button>\n             <button id="btn-dry-run" class="btn" style="padding:11px;" title="Dry-Run — simulasi tanpa ubah file">\n               <i data-lucide="shield"></i> Cek\n             </button>\n             <button class="btn" id="btn-clear-patch" style="padding:11px;" title="Bersihkan">\n               <i data-lucide="trash-2"></i>\n             </button>\n           </div>\n\n           <!-- Log panel — inline, sepanel dgn Edit (bukan overlay terpisah lagi). Zoom: pinch 2 jari langsung di sini -->\n           <div id="log-fullscreen">\n             <div id="log"></div>\n             <div class="log-zoom-indicator" id="log-zoom-indicator">100%</div>\n           </div>\n\n           <!-- Baris aksi log: autoscroll, copy, clear (zoom sudah lewat pinch, tombol dihapus) -->\n           <div class="log-actions-row" id="log-actions-row">\n             <button class="log-icon-btn on" id="btn-autoscroll-toggle" title="Auto-scroll">\n               <i data-lucide="arrow-down-to-line" style="width:13px"></i>\n             </button>\n             <input type="checkbox" id="chk-autoscroll" checked style="display:none">\n             <button class="log-icon-btn" id="btn-copy-log" title="Salin log">\n               <i data-lucide="copy" style="width:13px"></i>\n             </button>\n             <button class="log-icon-btn danger" id="btn-clear-log" title="Bersihkan">\n               <i data-lucide="trash" style="width:13px"></i>\n             </button>\n           </div>\n\n         </div>\n       </div>\n\n      <!-- VIEW: RESTORE SESSION -->\n      <div id="view-restore" class="view">\n         <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:15px; flex-wrap:wrap; gap:10px">\n           <div style="display:flex; align-items:center; gap:8px;">\n             <button id="restore-back-btn" class="btn" style="display:none" title="Kembali"><i data-lucide="arrow-left"></i></button>\n             <h2 style="margin:0; font-size:18px; font-weight:600;">Pulihkan Sesi</h2>\n           </div>\n           <div style="display:flex; align-items:center; gap:8px; flex-wrap:wrap;">\n             <div class="restore-mode-toggle">\n               <button class="restore-mode-btn active" data-mode="file"><i data-lucide="folder-open"></i> Per File</button>\n               <button class="restore-mode-btn" data-mode="commit"><i data-lucide="history"></i> Semua Commit</button>\n             </div>\n           </div>\n         </div>\n        <div class="github-box">\n          <div class="box-header"><span><i data-lucide="folder-git-2" style="width:14px; vertical-align:middle"></i> Riwayat</span></div>\n          <div class="box-body" id="restore-list">\n            <div style="padding:20px; text-align:center; color:var(--text-muted)">Memuat...</div>\n          </div>\n        </div>\n        <div id="restore-pagination"></div>\n        <div id="restore-detail"></div>\n        <div class="diff-zoom-indicator" id="diff-zoom-indicator">100%</div>\n      </div>\n\n      <!-- VIEW: SALIN PROMPT AI -->\n      <div id="view-promptai" class="view">\n        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:15px; flex-wrap:wrap; gap:10px">\n          <h2 style="margin:0; font-size:18px; font-weight:600;">Salin Prompt AI</h2>\n          <button class="btn btn-primary" id="btn-promptai-copy"><i data-lucide="copy" style="width:14px"></i> Salin ke Clipboard</button>\n        </div>\n        <div class="github-box">\n          <div class="box-header"><span><i data-lucide="file-text" style="width:14px; vertical-align:middle"></i> Teks Prompt Instruksi</span></div>\n          <div class="box-body" style="padding:0">\n            <pre id="promptai-text" style="margin:0; padding:15px; white-space:pre-wrap; word-break:break-word; font-family:monospace; font-size:12.5px; line-height:1.5; color:var(--text-main); max-height:65vh; overflow:auto;">Memuat...</pre>\n          </div>\n        </div>\n      </div>\n\n      <!-- VIEW: CEK SINTAKS -->\n      <div id="view-checksyntax" class="view">\n        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:15px; flex-wrap:wrap; gap:10px">\n          <h2 style="margin:0; font-size:18px; font-weight:600;">Cek Sintaks Python</h2>\n          <button class="ghost-btn" id="btn-checksyntax-refresh" title="Refresh daftar file"><i data-lucide="refresh-cw"></i></button>\n        </div>\n        <div class="github-box">\n          <div class="box-header"><span><i data-lucide="file-code" style="width:14px; vertical-align:middle"></i> Pilih File .py</span></div>\n          <div class="box-body" id="checksyntax-list">\n            <div style="padding:20px; text-align:center; color:var(--text-muted)">Memuat...</div>\n          </div>\n        </div>\n        <div id="checksyntax-result"></div>\n      </div>\n\n\n\n      <!-- VIEW: CARI & GANTI MANUAL -->\n      <div id="view-cari-ganti" class="view">\n        <div style="max-width:900px; margin:0 auto; width:100%; display:flex; flex-direction:column; gap:16px;">\n          <h2 style="margin:0; font-size:18px; font-weight:600;">Cari &amp; Ganti Manual</h2>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="search" style="width:14px;vertical-align:middle"></i> Kode yang dicari</span></div>\n            <div style="padding:12px">\n              <textarea id="cgm-find" style="width:100%; height:150px; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:10px; border-radius:6px; font-family:ui-monospace,monospace; font-size:13px; resize:vertical; line-height:1.5; outline:none;" placeholder="Tempel cuplikan kode yang ingin dicari di sini..."></textarea>\n            </div>\n          </div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="replace" style="width:14px;vertical-align:middle"></i> Kode pengganti</span><span style="font-size:12px;color:var(--text-muted)">Kosongkan = hapus</span></div>\n            <div style="padding:12px">\n              <textarea id="cgm-replace" style="width:100%; height:150px; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:10px; border-radius:6px; font-family:ui-monospace,monospace; font-size:13px; resize:vertical; line-height:1.5; outline:none;" placeholder="Tempel kode pengganti... (kosongkan untuk menghapus kode di atas)"></textarea>\n            </div>\n          </div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="file" style="width:14px;vertical-align:middle"></i> Hint file (opsional)</span></div>\n            <div style="padding:12px">\n              <input type="text" id="cgm-file" style="width:100%; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:8px 12px; border-radius:6px; font-family:ui-monospace,monospace; font-size:13px; outline:none;" placeholder="Contoh: src/main.py (kosongkan = cari otomatis di seluruh folder)">\n            </div>\n          </div>\n          <div style="display:flex; gap:10px;">\n            <button class="btn btn-primary" id="cgm-run" style="flex:1; justify-content:center; padding:12px;"><i data-lucide="play"></i> Cari &amp; Ganti</button>\n            <button class="btn" id="cgm-dry" style="padding:12px;" title="Simulasi tanpa mengubah file"><i data-lucide="shield"></i> Cek Saja</button>\n          </div>\n        </div>\n      </div>\n\n      <!-- VIEW: UBAH DIREKTORI -->\n      <div id="view-ubah-dir" class="view">\n        <div style="max-width:700px; margin:0 auto; width:100%; display:flex; flex-direction:column; gap:16px;">\n          <h2 style="margin:0; font-size:18px; font-weight:600;">Ubah Direktori Target</h2>\n          <div class="github-box">\n            <div class="box-header">\n              <span><i data-lucide="folder-open" style="width:14px;vertical-align:middle"></i> Direktori Aktif</span>\n              <button class="ghost-btn" id="btn-dir-refresh" title="Refresh"><i data-lucide="refresh-cw"></i></button>\n            </div>\n            <div style="padding:14px; font-family:monospace; font-size:13px; color:var(--accent); word-break:break-all;" id="dir-current">Memuat...</div>\n          </div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="history" style="width:14px;vertical-align:middle"></i> Riwayat Direktori</span></div>\n            <div id="dir-recent-list"><div style="padding:20px;text-align:center;color:var(--text-muted)">Memuat...</div></div>\n          </div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="keyboard" style="width:14px;vertical-align:middle"></i> Ketik Path Baru</span></div>\n            <div style="padding:12px; display:flex; gap:8px;">\n              <input type="text" id="dir-new-path" style="flex:1; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:8px 12px; border-radius:6px; font-family:monospace; font-size:13px; outline:none;" placeholder="/path/ke/folder/project">\n              <button class="btn btn-primary" id="dir-apply-new"><i data-lucide="check"></i> Terapkan</button>\n            </div>\n          </div>\n          <div id="dir-msg" style="display:none; padding:10px 14px; border-radius:8px; font-size:14px;"></div>\n        </div>\n      </div>\n\n      <!-- VIEW: SETUP AI -->\n      <div id="view-ai-setup" class="view">\n        <div style="max-width:800px; margin:0 auto; width:100%; display:flex; flex-direction:column; gap:16px;">\n          <div style="display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:10px;">\n            <h2 style="margin:0; font-size:18px; font-weight:600;">Setup AI Auto-Fix</h2>\n            <div id="ai-status-badge" style="font-size:13px; padding:5px 14px; border-radius:99px; background:var(--bg-panel); border:1px solid var(--border);">Memuat...</div>\n          </div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="server" style="width:14px;vertical-align:middle"></i> Step 1 — Pilih Provider</span></div>\n            <div id="ai-provider-list" style="padding:4px 0;"></div>\n          </div>\n          <div class="github-box">\n            <div class="box-header">\n              <span><i data-lucide="cpu" style="width:14px;vertical-align:middle"></i> Step 2 — Pilih Model</span>\n              <button class="ghost-btn" id="btn-ai-sync-models" title="Sinkronisasi model dari API"><i data-lucide="refresh-cw" style="width:14px;vertical-align:middle"></i> Sync</button>\n            </div>\n            <div id="ai-model-list" style="padding:4px 0;"></div>\n            <div style="padding:10px 16px; border-top:1px solid var(--border); display:flex; gap:8px; align-items:center;">\n              <input type="text" id="ai-model-manual" style="flex:1; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:7px 10px; border-radius:6px; font-family:monospace; font-size:13px; outline:none;" placeholder="Atau ketik ID model manual, mis: qwen/qwen-2.5-coder-32b-instruct:free">\n              <button class="btn" id="btn-ai-model-manual"><i data-lucide="check"></i> Pakai</button>\n            </div>\n          </div>\n          <div class="github-box">\n            <div class="box-header">\n              <span><i data-lucide="key" style="width:14px;vertical-align:middle"></i> Step 3 — API Key</span>\n              <button class="btn" id="btn-ai-test-key" style="padding:5px 10px; font-size:12px;"><i data-lucide="zap" style="width:12px"></i> Test Semua</button>\n            </div>\n            <div id="ai-key-hint" style="padding:8px 16px; font-size:12px; color:var(--text-muted); border-bottom:1px solid var(--border);"></div>\n            <div id="ai-key-list" style="padding:4px 0;"></div>\n            <div style="padding:10px 16px; border-top:1px solid var(--border); display:flex; gap:8px; align-items:center;">\n              <input type="text" id="ai-key-new" style="flex:1; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:7px 10px; border-radius:6px; font-family:monospace; font-size:13px; outline:none;" placeholder="Tempel API Key baru di sini...">\n              <button class="btn btn-primary" id="btn-ai-key-add"><i data-lucide="plus"></i> Tambah</button>\n            </div>\n            <div id="ai-test-result" style="padding:0 16px 10px; font-size:13px; line-height:1.7;"></div>\n          </div>\n        </div>\n      </div>\n\n      <!-- VIEW: IDENTITAS GIT -->\n      <div id="view-git-id" class="view">\n        <div style="max-width:600px; margin:0 auto; width:100%; display:flex; flex-direction:column; gap:16px;">\n          <h2 style="margin:0; font-size:18px; font-weight:600;">Identitas Git</h2>\n          <div style="color:var(--text-muted); font-size:14px;">Nama dan email ini dipakai FR Tool saat melakukan auto-commit ke repository.</div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="user" style="width:14px;vertical-align:middle"></i> Pengaturan Identitas</span></div>\n            <div style="padding:16px; display:flex; flex-direction:column; gap:14px;">\n              <div>\n                <label style="font-size:13px; font-weight:500; color:var(--text-muted); display:block; margin-bottom:6px;">Nama Commit</label>\n                <input type="text" id="git-name" style="width:100%; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:9px 12px; border-radius:6px; font-size:14px; outline:none;" placeholder="FR Tool">\n              </div>\n              <div>\n                <label style="font-size:13px; font-weight:500; color:var(--text-muted); display:block; margin-bottom:6px;">Email Commit</label>\n                <input type="text" id="git-email" style="width:100%; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:9px 12px; border-radius:6px; font-size:14px; outline:none;" placeholder="frtool@local">\n              </div>\n              <button class="btn btn-primary" id="btn-git-save" style="justify-content:center; padding:10px;"><i data-lucide="save"></i> Simpan Identitas</button>\n            </div>\n          </div>\n          <div id="git-id-msg" style="display:none; padding:10px 14px; border-radius:8px; font-size:14px;"></div>\n        </div>\n      </div>\n\n      <!-- VIEW: THRESHOLD -->\n      <div id="view-threshold" class="view">\n        <div style="max-width:600px; margin:0 auto; width:100%; display:flex; flex-direction:column; gap:16px;">\n          <h2 style="margin:0; font-size:18px; font-weight:600;">Threshold Matching</h2>\n          <div style="color:var(--text-muted); font-size:14px;">Atur batas toleransi pencocokan kode untuk auto-anchor dan partial scan.</div>\n          <div class="github-box">\n            <div class="box-header"><span><i data-lucide="sliders-horizontal" style="width:14px;vertical-align:middle"></i> Pengaturan Threshold</span></div>\n            <div style="padding:16px; display:flex; flex-direction:column; gap:16px;">\n              <div>\n                <label style="font-size:13px; font-weight:500; display:block; margin-bottom:4px;">Toleransi Auto-Anchor <span style="color:var(--text-muted); font-weight:400;">(jarak aman tanpa konfirmasi)</span></label>\n                <input type="number" id="thr-tolerance" style="width:100%; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:9px 12px; border-radius:6px; font-size:14px; outline:none;" min="0">\n              </div>\n              <div>\n                <label style="font-size:13px; font-weight:500; display:block; margin-bottom:4px;">Jarak Maksimal Anchor <span style="color:var(--text-muted); font-weight:400;">(wajib konfirmasi jika melebihi ini)</span></label>\n                <input type="number" id="thr-max-gap" style="width:100%; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:9px 12px; border-radius:6px; font-size:14px; outline:none;" min="0">\n              </div>\n              <div>\n                <label style="font-size:13px; font-weight:500; display:block; margin-bottom:4px;">Skor Minimal Partial Scan <span style="color:var(--text-muted); font-weight:400;">(0.0 – 1.0, mis: 0.30)</span></label>\n                <input type="number" id="thr-partial" style="width:100%; background:var(--bg-main); border:1px solid var(--border); color:var(--text-main); padding:9px 12px; border-radius:6px; font-size:14px; outline:none;" min="0" max="1" step="0.01">\n              </div>\n              <button class="btn btn-primary" id="btn-thr-save" style="justify-content:center; padding:10px;"><i data-lucide="save"></i> Simpan Threshold</button>\n            </div>\n          </div>\n          <div id="thr-msg" style="display:none; padding:10px 14px; border-radius:8px; font-size:14px;"></div>\n        </div>\n      </div>\n    </div>\n  </main>\n</div>\n\n<!-- Image Preview Lightbox — ala GitHub -->\n<div class="img-lightbox-overlay" id="img-lightbox" onclick="if(event.target===this) closeImagePreview()">\n  <div class="img-lightbox-header">\n    <span id="img-lightbox-name" style="overflow:hidden; text-overflow:ellipsis; white-space:nowrap;"></span>\n    <div style="display:flex; gap:4px; flex-shrink:0;">\n      <a id="img-lightbox-open" href="#" target="_blank" class="ghost-btn" title="Buka di tab baru"><i data-lucide="external-link"></i></a>\n      <button class="ghost-btn" title="Tutup" onclick="closeImagePreview()"><i data-lucide="x"></i></button>\n    </div>\n  </div>\n  <div class="img-lightbox-body">\n    <img id="img-lightbox-img" src="" alt="">\n  </div>\n</div>\n\n<!-- Modal Dialog -->\n<div class="modal-overlay" id="sheet">\n  <div id="modal">\n    <div class="sheet-header">\n      <div class="sheet-title" id="sheet-title"><i data-lucide="help-circle"></i><span id="sheet-title-text">Pertanyaan</span></div>\n    </div>\n    <div class="sheet-body" id="sheet-body"></div>\n  </div>\n</div>\n\n<script>\nlucide.createIcons();\n\n// Theme toggle (light/dark ala Claude)\n(function(){\n  var btn = document.getElementById(\'theme-toggle\');\n  if (!btn) return;\n  btn.addEventListener(\'click\', function(){\n    var isDark = document.documentElement.getAttribute(\'data-theme\') === \'dark\';\n    var meta = document.querySelector(\'meta[name="theme-color"]\');\n    if (isDark) {\n      document.documentElement.removeAttribute(\'data-theme\');\n      try { localStorage.setItem(\'frtool-theme\', \'light\'); } catch(e){}\n      if (meta) meta.setAttribute(\'content\', \'#faf9f5\');\n    } else {\n      document.documentElement.setAttribute(\'data-theme\', \'dark\');\n      try { localStorage.setItem(\'frtool-theme\', \'dark\'); } catch(e){}\n      if (meta) meta.setAttribute(\'content\', \'#262624\');\n    }\n  });\n})();\n\n// ANSI to HTML Converter (Optimized)\nconst ANSI_BASIC = {\n  30:\'#000000\',31:\'#ff7b72\',32:\'#3fb950\',33:\'#d29922\',34:\'#58a6ff\',35:\'#bc8cff\',36:\'#39c5cf\',37:\'#c9d1d9\',\n  90:\'#8b949e\',91:\'#ffa198\',92:\'#56d364\',93:\'#e3b341\',94:\'#79c0ff\',95:\'#d2a8ff\',96:\'#56d4dd\',97:\'#f0f6fc\'\n};\n// 256-color palette index → CSS color string\nfunction ansi256(n) {\n  if (n < 8)  return ANSI_BASIC[30 + n];\n  if (n < 16) return ANSI_BASIC[90 + (n - 8)];\n  if (n < 232) {\n    const i = n - 16, r = Math.floor(i / 36), g = Math.floor((i % 36) / 6), b = i % 6;\n    const v = [0, 95, 135, 175, 215, 255];\n    return `rgb(${v[r]},${v[g]},${v[b]})`;\n  }\n  const gray = (n - 232) * 10 + 8;\n  return `rgb(${gray},${gray},${gray})`;\n}\nfunction escapeHtml(s) { return (s || \'\').replace(/[&<>"\']/g, c => ({\'&\':\'&amp;\',\'<\':\'&lt;\',\'>\':\'&gt;\',\'"\':\'&quot;\',"\'":\'&#39;\'}[c])); }\nfunction ansiToHtml(text) {\n  const re = /\\x1b\\[([0-9;]*)m/g; let prevEnd = 0, m, out = \'\', spanOpen = false;\n  let fg = null, bg = null, bold = false;\n  function styleStr() {\n    const s = [];\n    if (fg)   s.push(\'color:\' + fg);\n    if (bg)   s.push(\'background-color:\' + bg);\n    if (bold) s.push(\'font-weight:bold\');\n    return s.join(\';\');\n  }\n  function flushText(end) {\n    const chunk = escapeHtml(text.slice(prevEnd, end));\n    if (!chunk) return;\n    const st = styleStr();\n    if (st) { if (!spanOpen) { out += \'<span style="\' + st + \'">\'; spanOpen = true; } }\n    else    { if ( spanOpen) { out += \'</span>\';                     spanOpen = false; } }\n    out += chunk;\n  }\n  while ((m = re.exec(text)) !== null) {\n    flushText(m.index);\n    if (spanOpen) { out += \'</span>\'; spanOpen = false; }\n    // Parse codes with index so multi-arg sequences (38;5;n, 38;2;r;g;b) work\n    const codes = m[1] ? m[1].split(\';\').map(Number) : [0];\n    let i = 0;\n    while (i < codes.length) {\n      const c = codes[i];\n      if (c === 0)  { fg = null; bg = null; bold = false; }\n      else if (c === 1) bold = true;\n      else if (c === 22) bold = false;\n      else if (c === 39) fg = null;\n      else if (c === 49) bg = null;\n      // 256-color foreground: 38;5;n\n      else if (c === 38 && codes[i+1] === 5 && i+2 < codes.length) { fg = ansi256(codes[i+2]); i += 2; }\n      // 256-color background: 48;5;n\n      else if (c === 48 && codes[i+1] === 5 && i+2 < codes.length) { bg = ansi256(codes[i+2]); i += 2; }\n      // TrueColor foreground: 38;2;r;g;b\n      else if (c === 38 && codes[i+1] === 2 && i+4 <= codes.length) { fg = `rgb(${codes[i+2]},${codes[i+3]},${codes[i+4]})`; i += 4; }\n      // TrueColor background: 48;2;r;g;b\n      else if (c === 48 && codes[i+1] === 2 && i+4 <= codes.length) { bg = `rgb(${codes[i+2]},${codes[i+3]},${codes[i+4]})`; i += 4; }\n      // Basic FG 30-37, bright FG 90-97\n      else if (ANSI_BASIC[c]) fg = ANSI_BASIC[c];\n      // Basic BG 40-47 → map to FG key (c-10)\n      else if (c >= 40 && c <= 47) bg = ANSI_BASIC[c - 10];\n      // Bright BG 100-107 → map to bright FG key (c-60)\n      else if (c >= 100 && c <= 107) bg = ANSI_BASIC[c - 60];\n      i++;\n    }\n    prevEnd = re.lastIndex;\n  }\n  flushText(text.length);\n  if (spanOpen) out += \'</span>\';\n  return out;\n}\n\n// Elements\nconst logEl = document.getElementById(\'log\');\nconst statusPill = document.getElementById(\'status-pill\');\nconst statusPillText = document.getElementById(\'status-pill-text\');\nconst btnApply = document.getElementById(\'btn-apply\');\nconst btnDryRun = document.getElementById(\'btn-dry-run\');\nconst patchEl = document.getElementById(\'patch\');\nconst folderEl = document.getElementById(\'folder\');\nconst sheetEl = document.getElementById(\'sheet\');\nconst sheetBodyEl = document.getElementById(\'sheet-body\');\nconst sheetTitleTextEl = document.getElementById(\'sheet-title-text\');\nconst repoFileList = document.getElementById(\'repo-file-list\');\n\nlet currentJobId = null;\nlet currentRepoPath = \'\';\n\n// Terminal emulator\nconst term = { rows: [], cur: 0 };\nfunction getRow(i) {\n  while (term.rows.length <= i) {\n    const el = document.createElement(\'div\'); el.className = \'term-row\';\n    logEl.appendChild(el); term.rows.push({el, raw: \'\'});\n  }\n  return term.rows[i];\n}\nfunction stripSgr(s) { return s.replace(/\\x1b\\[[0-9;]*m/g, \'\'); }\n\nconst BOX_BORDER_RE = /^[\\s\\u2500-\\u257F\\u2550-\\u256C\\u2016]+$/;\n\nconst DIFF_GUTTER_RE = /^(\\s*\\d+[+\\-]?\\s+)/;\n\nfunction renderRow(i) {\n  const row = term.rows[i]; if (!row) return;\n  let plain = stripSgr(row.raw);\n  if (BOX_BORDER_RE.test(plain)) { row.el.style.display = \'none\'; return; }\n  \n  let m = plain.match(/^\\[(.*?)\\] (.*)$/);\n  if (m && [\'OK\',\'GAGAL\',\'SKIP\',\'INFO\',\'ERROR\'].includes(m[1])) {\n    let cls = m[1]===\'OK\'?\'ok\':(m[1]===\'GAGAL\'||m[1]===\'ERROR\')?\'err\':\'skip\';\n    row.el.innerHTML = `<span class="log-badge ${cls}">${m[1]}</span><span>${ansiToHtml(row.raw.slice(m[0].length-m[2].length))}</span>`;\n    row.el.classList.remove(\'diff-gutter-row\');\n    return;\n  }\n  row.el.innerHTML = ansiToHtml(row.raw);\n\n  // Baris diff bernomor (preview patch): kalau wrap, sambungannya disejajarkan\n  // ke kode itu sendiri — bukan nempel balik ke kolom nomor baris.\n  const gm = plain.match(DIFF_GUTTER_RE);\n  if (gm) {\n    row.el.classList.add(\'diff-gutter-row\');\n    row.el.style.setProperty(\'--gutter-ch\', gm[1].length);\n  } else {\n    row.el.classList.remove(\'diff-gutter-row\');\n  }\n}\n\nfunction appendLog(text) {\n  const re = /\\x1b\\[([0-9;]*)([mKA])|\\r|\\n/g;\n  let last = 0, mm;\n  while ((mm = re.exec(text)) !== null) {\n    if (mm.index > last) getRow(term.cur).raw += text.slice(last, mm.index);\n    if (mm[0] === \'\\r\') getRow(term.cur).raw = \'\';\n    else if (mm[0] === \'\\n\') {\n      const r = getRow(term.cur).raw.replace(/\\x1b\\[[0-9;?]*[a-zA-Z]/g, \'\').trim();\n      if (/^[\\s=*\\-:.#]{5,}$/.test(r)) getRow(term.cur).raw = \'\'; else { renderRow(term.cur); term.cur++; }\n    }\n    else if (mm[2] === \'m\') getRow(term.cur).raw += mm[0];\n    else if (mm[2] === \'A\') term.cur = Math.max(0, term.cur - parseInt(mm[1] || \'1\', 10));\n    last = re.lastIndex;\n  }\n  if (last < text.length) getRow(term.cur).raw += text.slice(last);\n  renderRow(term.cur);\n  if (document.getElementById(\'chk-autoscroll\').checked) logEl.scrollTop = logEl.scrollHeight;\n}\n\nfunction setStatus(mode, text) {\n  statusPill.className = \'status-pill \' + mode;\n  statusPillText.textContent = text;\n}\n\n// Sidebar Navigation\nfunction switchView(viewId) {\n  const incoming = document.getElementById(\'view-\' + viewId);\n  const outgoing = document.querySelector(\'.view.active\');\n\n  // Nav highlight\n  document.querySelectorAll(\'.sidebar-nav .nav-btn\').forEach(b => b.classList.remove(\'active\'));\n  const navBtn = document.querySelector(`.sidebar-nav .nav-btn[data-view="${viewId}"]`);\n  if (navBtn) navBtn.classList.add(\'active\');\n  if (window.innerWidth <= 768) toggleSidebar(false);\n\n  // Init hooks\n  if (viewId === \'restore\'     && !restoreInited)     { restoreInited     = true; restoreInit(); }\n  if (viewId === \'promptai\'    && !promptAiInited)    { promptAiInited    = true; promptAiInit(); }\n  if (viewId === \'checksyntax\' && !checksyntaxInited) { checksyntaxInited = true; checksyntaxInit(); }\n  if (viewId === \'threshold\') thrLoad();\n  if (viewId === \'git-id\')    gitIdLoad();\n  if (viewId === \'ubah-dir\')  dirLoad();\n  if (viewId === \'ai-setup\')  aiSetupLoad();\n\n  if (outgoing === incoming) return;\n\n  // GSAP: slide-out current, slide-in next\n  const tl = gsap.timeline();\n  if (outgoing) {\n    tl.to(outgoing, {\n      opacity: 0, y: -8, duration: 0.18, ease: \'power2.in\',\n      onComplete() { outgoing.classList.remove(\'active\'); gsap.set(outgoing, { clearProps: \'all\' }); }\n    });\n  }\n  incoming.classList.add(\'active\');\n  gsap.set(incoming, { opacity: 0, y: 12 });\n  tl.to(incoming, { opacity: 1, y: 0, duration: 0.26, ease: \'power3.out\' }, outgoing ? \'+=0.02\' : 0);\n}\n\ndocument.querySelectorAll(\'.nav-btn[data-view]\').forEach(btn => {\n  btn.onclick = () => switchView(btn.dataset.view);\n});\n\nfunction toggleSidebar(force) {\n  const sb = document.getElementById(\'sidebar\');\n  const ov = document.getElementById(\'sidebar-overlay\');\n  const isOpen = force !== undefined ? force : !sb.classList.contains(\'open\');\n  sb.classList.toggle(\'open\', isOpen);\n  ov.classList.toggle(\'open\', isOpen);\n}\ndocument.getElementById(\'menu-toggle\').onclick = () => toggleSidebar();\ndocument.getElementById(\'sidebar-overlay\').onclick = () => toggleSidebar(false);\n\n// Textarea patch sekarang native murni — tanpa overlay/highlight, jadi tidak\n// perlu sinkronisasi apapun lagi. Kursor 100% presisi karena cuma ada SATU\n// elemen yang me-render teks (browser sendiri yang pegang penuh, bukan hack\n// 2 elemen numpuk kayak sebelumnya).\n\n// Format ukuran file ala GitHub (B/KB/MB)\nfunction formatBytes(bytes) {\n  if (!bytes || bytes <= 0) return \'\';\n  if (bytes < 1024) return bytes + \' B\';\n  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + \' KB\';\n  return (bytes / (1024 * 1024)).toFixed(1) + \' MB\';\n}\n\n// Load Repo Data\nconst IMAGE_EXT_RE = /\\.(png|jpe?g|gif|webp|svg|bmp|ico|avif)$/i;\n\nfunction openImagePreview(relpath, name) {\n  const url = \'/api/repo_file_raw?path=\' + encodeURIComponent(relpath);\n  document.getElementById(\'img-lightbox-img\').src = url;\n  document.getElementById(\'img-lightbox-name\').textContent = name;\n  document.getElementById(\'img-lightbox-open\').href = url;\n  document.getElementById(\'img-lightbox\').classList.add(\'open\');\n}\nfunction closeImagePreview() {\n  document.getElementById(\'img-lightbox\').classList.remove(\'open\');\n  document.getElementById(\'img-lightbox-img\').src = \'\';\n}\n\nfunction loadRepo(path = \'\') {\n  currentRepoPath = path;\n  fetch(\'/api/repo_data?path=\' + encodeURIComponent(path))\n    .then(r => r.json())\n    .then(data => {\n      document.getElementById(\'header-repo-name\').textContent = data.root.split(\'/\').pop() || data.root;\n      folderEl.placeholder = data.root;\n      document.getElementById(\'stat-commits\').textContent = data.commits;\n      document.getElementById(\'stat-latest-commit\').textContent = data.latest_commit;\n      if(data.branch !== \'HEAD\') {\n        document.getElementById(\'header-branch-badge\').style.display = \'inline-flex\';\n        document.getElementById(\'header-branch\').textContent = data.branch;\n      }\n      \n      const cpEl = document.getElementById(\'current-path\');\n      const rootPath = data.root || \'/\';\n      let crumbs = \'<span style="cursor:pointer;font-weight:600" onclick="loadRepo(\\\'\\\')" title="\' + escapeHtml(rootPath) + \'">\' + escapeHtml(rootPath) + \'</span>\';\n      if (data.path) {\n        const segs = data.path.split(\'/\');\n        let acc = \'\';\n        segs.forEach((seg) => {\n          acc = acc ? acc + \'/\' + seg : seg;\n          crumbs += \'<span style="opacity:.6">/</span>\' + \'<span style="cursor:pointer" onclick="loadRepo(\\\'\' + acc.replace(/\'/g, "\\\\\'") + \'\\\')">\' + escapeHtml(seg) + \'</span>\';\n        });\n      }\n      cpEl.innerHTML = crumbs;\n      \n      let html = \'\';\n      if (data.path) {\n        let parent = data.path.split(\'/\').slice(0,-1).join(\'/\');\n        html += `<div class="file-row" onclick="loadRepo(\'${parent}\')">\n                   <div class="file-icon folder"><i data-lucide="corner-left-up"></i></div>\n                   <div class="file-name" style="font-weight:600; color:var(--accent)">..</div>\n                 </div>`;\n      }\n      \n      data.items.forEach(item => {\n        const relItem = data.path ? data.path + \'/\' + item.name : item.name;\n        const isImage = !item.is_dir && IMAGE_EXT_RE.test(item.name);\n        let icon = item.is_dir ? \'<i data-lucide="folder"></i>\' : (isImage ? \'<i data-lucide="image"></i>\' : \'<i data-lucide="file"></i>\');\n        let cls = item.is_dir ? \'folder\' : \'\';\n        let onClick = item.is_dir\n          ? `onclick="loadRepo(\'${relItem}\')"`\n          : (isImage ? `onclick="openImagePreview(\'${relItem.replace(/\'/g, "\\\\\'")}\', \'${escapeHtml(item.name).replace(/\'/g, "\\\\\'")}\')"` : \'\');\n        let metaBits = [];\n        if (item.commit_msg) metaBits.push(escapeHtml(item.commit_msg));\n        if (item.commit_time) metaBits.push(item.commit_time);\n        let meta = metaBits.length ? `<div class="file-meta"><i data-lucide="git-commit"></i>${metaBits.join(\' &middot; \')}</div>` : \'\';\n        let sizeBadge = (!item.is_dir && item.size) ? `<span class="file-size-badge">${formatBytes(item.size)}</span>` : \'\';\n        html += `<div class="file-row repo-row" ${onClick}>\n                   <div class="file-icon ${cls}">${icon}</div>\n                   <div class="file-main">\n                     <div class="file-name">${escapeHtml(item.name)}${sizeBadge}</div>\n                     ${meta}\n                   </div>\n                 </div>`;\n      });\n      if(data.items.length === 0) html += \'<div style="padding:20px;text-align:center;color:var(--text-muted)">Folder kosong</div>\';\n      \n      repoFileList.innerHTML = html;\n\n      const readmeBox = document.getElementById(\'repo-readme-box\');\n      if (data.readme) {\n        let body = `<div class="box-header"><span style="display:flex;align-items:center;gap:6px;"><i data-lucide="book-open" style="width:14px;"></i> ${escapeHtml(data.readme.name)}</span></div>\n                     <div class="repo-readme-body">${escapeHtml(data.readme.content)}</div>`;\n        if (data.readme.truncated) body += `<div class="repo-readme-truncated">Ditampilkan sebagian &mdash; file lengkapnya lebih panjang.</div>`;\n        readmeBox.innerHTML = body;\n        readmeBox.style.display = \'\';\n      } else {\n        readmeBox.style.display = \'none\';\n      }\n\n      lucide.createIcons();\n    });\n}\ndocument.getElementById(\'btn-change-dir\').onclick = () => switchView(\'ubah-dir\');\nloadRepo();\n\n// ============ RESTORE SESSION (Pulihkan Sesi) ============\nlet restoreInited = false;\nlet restoreMode = \'file\';\nlet restoreCommitsAll = [];\nlet restoreCommitsPage = 1;\nconst RESTORE_PAGE_SIZE = 15;\nlet restoreNavStack = [];\n\nfunction restoreSnapshot() {\n  return {\n    mode: restoreMode,\n    page: restoreCommitsPage,\n    listHtml: document.getElementById(\'restore-list\').innerHTML,\n    detailHtml: document.getElementById(\'restore-detail\').innerHTML,\n    pagerHtml: document.getElementById(\'restore-pagination\').innerHTML,\n  };\n}\n\nfunction restoreNavPush() {\n  restoreNavStack.push(restoreSnapshot());\n  document.getElementById(\'restore-back-btn\').style.display = \'inline-flex\';\n  history.pushState({ restoreNavDepth: restoreNavStack.length }, \'\');\n}\n\nfunction restoreNavBack() {\n  if (!restoreNavStack.length) return;\n  const snap = restoreNavStack.pop();\n  restoreMode = snap.mode;\n  restoreCommitsPage = snap.page;\n  document.getElementById(\'restore-list\').innerHTML = snap.listHtml;\n  document.getElementById(\'restore-detail\').innerHTML = snap.detailHtml;\n  document.getElementById(\'restore-pagination\').innerHTML = snap.pagerHtml;\n  document.querySelectorAll(\'.restore-mode-btn\').forEach(b => b.classList.toggle(\'active\', b.dataset.mode === restoreMode));\n  document.getElementById(\'restore-back-btn\').style.display = restoreNavStack.length ? \'inline-flex\' : \'none\';\n  lucide.createIcons();\n}\n\nwindow.addEventListener(\'popstate\', function() {\n  const viewRestore = document.getElementById(\'view-restore\');\n  if (viewRestore && viewRestore.classList.contains(\'active\') && restoreNavStack.length) {\n    restoreNavBack();\n  }\n});\n\nfunction restoreAnimatePageSwap(renderFn) {\n  const el = document.getElementById(\'restore-list\');\n  const rows = el.querySelectorAll(\'.file-row\');\n  const tl = gsap.timeline();\n  if (rows.length) {\n    tl.to(rows, { opacity: 0, y: -8, duration: 0.16, ease: \'power2.in\', stagger: 0.02 });\n  }\n  tl.call(() => {\n    renderFn();\n    el.scrollTop = 0;\n    const newRows = el.querySelectorAll(\'.file-row\');\n    gsap.fromTo(newRows, { opacity: 0, y: 10 }, { opacity: 1, y: 0, duration: 0.28, ease: \'power2.out\', stagger: 0.035 });\n  });\n}\n\nfunction restoreInit() {\n  document.querySelectorAll(\'.restore-mode-btn\').forEach(b => {\n    b.onclick = () => { restoreMode = b.dataset.mode; renderRestoreMode(); };\n  });\n  document.getElementById(\'restore-back-btn\').onclick = () => history.back();\n  renderRestoreMode();\n}\n\nfunction renderRestoreMode() {\n  document.querySelectorAll(\'.restore-mode-btn\').forEach(b => b.classList.toggle(\'active\', b.dataset.mode === restoreMode));\n  document.getElementById(\'restore-detail\').innerHTML = \'\';\n  document.getElementById(\'restore-pagination\').innerHTML = \'\';\n  document.getElementById(\'restore-list\').scrollTop = 0;\n  restoreNavStack = [];\n  document.getElementById(\'restore-back-btn\').style.display = \'none\';\n  if (restoreMode === \'file\') restoreBrowse(\'\', true); else restoreLoadCommits();\n}\n\n// Dipicu dari kartu "Total Commits" di panel Repository: buka Pulihkan Sesi tab Semua Commit\nfunction openRestoreCommitsList() {\n  restoreMode = \'commit\';\n  switchView(\'restore\');\n  renderRestoreMode();\n}\n\n// Dipicu dari kartu "Latest Commit" di panel Repository: buka Pulihkan Sesi & langsung tampilkan preview diff commit terakhir\nfunction openLatestCommitDiff() {\n  restoreMode = \'commit\';\n  switchView(\'restore\');\n  document.querySelectorAll(\'.restore-mode-btn\').forEach(b => b.classList.toggle(\'active\', b.dataset.mode === \'commit\'));\n  document.getElementById(\'restore-detail\').innerHTML = \'\';\n  document.getElementById(\'restore-pagination\').innerHTML = \'\';\n  restoreNavStack = [];\n  document.getElementById(\'restore-back-btn\').style.display = \'none\';\n  fetch(\'/api/restore/commits\').then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat commit\', false);\n    restoreCommitsAll = d.entries || [];\n    restoreCommitsPage = 1;\n    renderRestoreCommitsPage();\n    if (d.head_hash) restoreCommitDetailAutoDiff(d.head_hash);\n  });\n}\n\n// Sama seperti restoreCommitDetail(), tapi otomatis langsung menampilkan preview diff\n// code untuk semua file yang berubah (tanpa perlu tap manual satu-satu per file)\nfunction restoreCommitDetailAutoDiff(hash) {\n  restoreNavPush();\n  fetch(\'/api/restore/commit_files?hash=\' + hash).then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat commit\', false);\n    let html = `<div class="github-box" style="margin-top:12px">\n                  <div class="box-header"><span>Diubah pada commit ${hash}</span></div>`;\n    if (!d.changed_files.length) {\n      html += \'<div style="padding:20px;text-align:center;color:var(--text-muted)">Tidak ada perubahan tercatat</div>\';\n    } else {\n      d.changed_files.forEach(f => {\n        html += `<div class="file-row" onclick="restoreShowFileDiffInCommit(\'${hash}\',\'${f}\')">\n                   <div class="file-icon"><i data-lucide="file-diff"></i></div>\n                   <div class="file-name">${escapeHtml(f)}</div>\n                 </div>`;\n      });\n    }\n    html += `</div><div class="patch-actions" style="margin-top:12px">\n               <button class="btn btn-primary" style="flex:1;justify-content:center" onclick="restoreApplyCommit(\'${hash}\')"><i data-lucide="history"></i> Pulihkan ke Commit Ini</button>\n             </div><div id="restore-diff-slot"></div>`;\n    document.getElementById(\'restore-detail\').innerHTML = html;\n    lucide.createIcons();\n    document.getElementById(\'restore-detail\').scrollIntoView({ behavior: \'smooth\', block: \'start\' });\n\n    const slot = document.getElementById(\'restore-diff-slot\');\n    (d.changed_files || []).forEach(f => {\n      fetch(\'/api/restore/diff?hash=\' + hash + \'&relpath=\' + encodeURIComponent(f)).then(r => r.json()).then(dd => {\n        const wrap = document.createElement(\'div\');\n        wrap.style.marginTop = \'12px\';\n        wrap.innerHTML = renderDiffPanel(dd, f);\n        slot.appendChild(wrap);\n        lucide.createIcons();\n      });\n    });\n  });\n}\n\nfunction restoreToast(msg, ok) {\n  const t = document.createElement(\'div\');\n  t.className = \'restore-toast \' + (ok ? \'ok\' : \'err\');\n  t.textContent = msg;\n  document.body.appendChild(t);\n  setTimeout(() => t.classList.add(\'show\'), 10);\n  setTimeout(() => { t.classList.remove(\'show\'); setTimeout(() => t.remove(), 300); }, 3000);\n}\n\n// Salin Prompt AI (native, tanpa job/CLI — pakai clipboard browser langsung)\nlet promptAiInited = false;\nlet promptAiText = \'\';\nfunction promptAiInit() {\n  const el = document.getElementById(\'promptai-text\');\n  fetch(\'/api/prompt_ai\').then(r => r.json()).then(d => {\n    if (!d.ok) { el.textContent = d.error || \'Gagal memuat prompt.\'; return; }\n    promptAiText = d.text;\n    el.textContent = d.text;\n  }).catch(() => { el.textContent = \'Gagal memuat prompt (koneksi error).\'; });\n}\ndocument.getElementById(\'btn-promptai-copy\').onclick = () => {\n  if (!promptAiText) return;\n  const fallbackCopy = () => {\n    const ta = document.createElement(\'textarea\');\n    ta.value = promptAiText; ta.style.position = \'fixed\'; ta.style.opacity = \'0\';\n    document.body.appendChild(ta); ta.focus(); ta.select();\n    try { document.execCommand(\'copy\'); restoreToast(\'Prompt disalin ke clipboard.\', true); }\n    catch (e) { restoreToast(\'Gagal menyalin otomatis, pilih teks secara manual.\', false); }\n    document.body.removeChild(ta);\n  };\n  if (navigator.clipboard && navigator.clipboard.writeText) {\n    navigator.clipboard.writeText(promptAiText).then(() => restoreToast(\'Prompt disalin ke clipboard.\', true)).catch(fallbackCopy);\n  } else fallbackCopy();\n};\n\n// Cek Sintaks Python (native, tanpa job/CLI)\nlet checksyntaxInited = false;\nfunction checksyntaxInit() {\n  document.getElementById(\'btn-checksyntax-refresh\').onclick = checksyntaxLoadFiles;\n  checksyntaxLoadFiles();\n}\nfunction checksyntaxLoadFiles() {\n  const listEl = document.getElementById(\'checksyntax-list\');\n  listEl.innerHTML = \'<div style="padding:20px; text-align:center; color:var(--text-muted)">Memuat...</div>\';\n  document.getElementById(\'checksyntax-result\').innerHTML = \'\';\n  fetch(\'/api/checksyntax/files\').then(r => r.json()).then(d => {\n    if (!d.ok) { listEl.innerHTML = `<div style="padding:20px; text-align:center; color:var(--err)">${escapeHtml(d.error || \'Gagal memuat daftar file\')}</div>`; return; }\n    if (!d.files.length) { listEl.innerHTML = \'<div style="padding:20px; text-align:center; color:var(--text-muted)">Tidak ada file .py ditemukan di folder ini</div>\'; return; }\n    let html = \'\';\n    d.files.forEach(f => {\n      html += `<div class="file-row" onclick="checksyntaxRun(\'${f.rel.replace(/\'/g, "\\\\\'")}\')">\n                 <div class="file-icon"><i data-lucide="file-code-2"></i></div>\n                 <div class="file-name">${escapeHtml(f.rel)}</div>\n                 ${f.is_self ? \'<div class="file-date">← tool ini sendiri</div>\' : \'\'}\n               </div>`;\n    });\n    listEl.innerHTML = html;\n    lucide.createIcons();\n  }).catch(() => { listEl.innerHTML = \'<div style="padding:20px; text-align:center; color:var(--err)">Gagal memuat daftar file (koneksi error).</div>\'; });\n}\nfunction checksyntaxRun(rel) {\n  const resEl = document.getElementById(\'checksyntax-result\');\n  resEl.innerHTML = \'<div class="github-box" style="margin-top:12px"><div style="padding:20px; text-align:center; color:var(--text-muted)">Mengecek sintaks...</div></div>\';\n  fetch(\'/api/checksyntax/run\', { method: \'POST\', body: JSON.stringify({ rel }) }).then(r => r.json()).then(d => {\n    if (!d.ok) { resEl.innerHTML = `<div class="github-box" style="margin-top:12px; border-color:var(--err)"><div style="padding:16px; color:var(--err)">${escapeHtml(d.error || \'Gagal mengecek file\')}</div></div>`; return; }\n    if (d.valid) {\n      resEl.innerHTML = `<div class="github-box" style="margin-top:12px; border-color:var(--ok)">\n        <div class="box-header"><span style="color:var(--ok)"><i data-lucide="check-circle-2" style="width:14px;vertical-align:middle"></i> AMAN</span></div>\n        <div style="padding:16px">\n          <div>${escapeHtml(d.rel)} — tidak ada syntax error (${d.lines} baris).</div>\n          <div style="color:var(--text-muted); font-size:13px; margin-top:6px">File ini sudah pasti bisa di-parse Python, aman untuk dipakai/restart.</div>\n        </div>\n      </div>`;\n    } else {\n      const e = d.err;\n      const pointer = \' \'.repeat(Math.max(0, e.offset - 1)) + \'^\';\n      resEl.innerHTML = `<div class="github-box" style="margin-top:12px; border-color:var(--err)">\n        <div class="box-header"><span style="color:var(--err)"><i data-lucide="alert-circle" style="width:14px;vertical-align:middle"></i> ADA ERROR</span></div>\n        <div style="padding:16px">\n          <div>${escapeHtml(d.rel)} — SyntaxError baris ${e.lineno}, kolom ${e.offset}</div>\n          <div style="color:var(--err); margin-top:4px">Pesan: ${escapeHtml(e.msg)}</div>\n          <pre style="background:var(--bg-panel); padding:10px; border-radius:6px; margin-top:10px; overflow-x:auto; font-family:monospace; font-size:13px; white-space:pre">${escapeHtml(String(e.lineno).padStart(5, \' \'))} │ ${escapeHtml(e.text)}\n      │ ${escapeHtml(pointer)}</pre>\n          <div style="color:var(--warn); margin-top:10px; font-size:13px">⚠ Jangan restart tool pakai file ini dulu — perbaiki errornya, cek ulang.</div>\n        </div>\n      </div>`;\n    }\n    lucide.createIcons();\n  }).catch(() => { resEl.innerHTML = \'<div class="github-box" style="margin-top:12px; border-color:var(--err)"><div style="padding:16px; color:var(--err)">Gagal mengecek file (koneksi error).</div></div>\'; });\n}\n\nfunction restoreConfirm(title, message, onYes) {\n  sheetTitleTextEl.textContent = title;\n  sheetBodyEl.innerHTML = `<p>${escapeHtml(message)}</p><div class="sheet-opts">\n    <button class="btn btn-primary" id="rc-yes">Ya, Lanjutkan</button>\n    <button class="btn" id="rc-no">Batal</button></div>`;\n  sheetEl.classList.add(\'open\');\n  gsap.fromTo("#modal", {y: 50, opacity: 0}, {y: 0, opacity: 1, duration: 0.3, ease: "power2.out"});\n  document.getElementById(\'rc-yes\').onclick = () => { closeSheet(); onYes(); };\n  document.getElementById(\'rc-no\').onclick = () => closeSheet();\n}\n\nfunction restoreBrowse(path, skipPush) {\n  if (!skipPush) restoreNavPush();\n  fetch(\'/api/restore/browse?path=\' + encodeURIComponent(path)).then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat folder\', false);\n    let html = `<div class="restore-breadcrumb">${escapeHtml(d.path ? \'/\' + d.path : \'/ (root)\')}</div>`;\n    if (!d.path && d.deleted_count > 0) {\n      html += `<div class="file-row" onclick="restoreShowDeleted()">\n                 <div class="file-icon"><i data-lucide="trash-2"></i></div>\n                 <div class="file-name">Lihat file yang sudah dihapus (${d.deleted_count})</div>\n               </div>`;\n    }\n    if (d.path) {\n      const parent = d.path.split(\'/\').slice(0, -1).join(\'/\');\n      html += `<div class="file-row" onclick="restoreBrowse(\'${parent}\')">\n                 <div class="file-icon folder"><i data-lucide="corner-left-up"></i></div>\n                 <div class="file-name" style="font-weight:600;color:var(--accent)">..</div>\n               </div>`;\n    }\n    d.dirs.forEach(dn => {\n      const p = d.path ? d.path + \'/\' + dn : dn;\n      html += `<div class="file-row" onclick="restoreBrowse(\'${p}\')">\n                 <div class="file-icon folder"><i data-lucide="folder"></i></div>\n                 <div class="file-name">${escapeHtml(dn)}</div>\n               </div>`;\n    });\n    d.files.forEach(fn => {\n      const p = d.path ? d.path + \'/\' + fn : fn;\n      html += `<div class="file-row" onclick="restoreShowHistory(\'${p}\')">\n                 <div class="file-icon"><i data-lucide="file"></i></div>\n                 <div class="file-name">${escapeHtml(fn)}</div>\n               </div>`;\n    });\n    if (!d.dirs.length && !d.files.length && !(!d.path && d.deleted_count > 0)) {\n      html += \'<div style="padding:20px;text-align:center;color:var(--text-muted)">Folder kosong</div>\';\n    }\n    document.getElementById(\'restore-list\').innerHTML = html;\n    document.getElementById(\'restore-detail\').innerHTML = \'\';\n    lucide.createIcons();\n  });\n}\n\nfunction restoreShowDeleted() {\n  restoreNavPush();\n  fetch(\'/api/restore/deleted\').then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat data\', false);\n    let html = `<div class="restore-breadcrumb">🗑 File terhapus/di-rename (${d.items.length})</div>`;\n    html += `<div class="file-row" onclick="restoreBrowse(\'\')">\n               <div class="file-icon folder"><i data-lucide="corner-left-up"></i></div>\n               <div class="file-name" style="font-weight:600;color:var(--accent)">..</div>\n             </div>`;\n    d.items.forEach(fn => {\n      html += `<div class="file-row" onclick="restoreShowHistory(\'${fn}\')">\n                 <div class="file-icon"><i data-lucide="file-x"></i></div>\n                 <div class="file-name">${escapeHtml(fn)}</div>\n               </div>`;\n    });\n    document.getElementById(\'restore-list\').innerHTML = html;\n    lucide.createIcons();\n  });\n}\n\nfunction restoreShowHistory(relpath, skipPush) {\n  if (!skipPush) restoreNavPush();\n  fetch(\'/api/restore/file_history?relpath=\' + encodeURIComponent(relpath)).then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat riwayat\', false);\n    let html = `<div class="github-box" style="margin-top:12px">\n                  <div class="box-header"><span><i data-lucide="file" style="width:14px;vertical-align:middle"></i> ${escapeHtml(relpath)}</span></div>`;\n    if (!d.entries.length) {\n      html += \'<div style="padding:20px;text-align:center;color:var(--text-muted)">Tidak ada riwayat commit</div>\';\n    } else {\n      d.entries.forEach(e => {\n        html += `<div class="file-row" onclick="restoreFileDiff(\'${relpath}\',\'${e.hash}\')">\n                   <div class="file-icon"><i data-lucide="git-commit"></i></div>\n                   <div class="file-name">${escapeHtml(e.msg)}</div>\n                   <div class="file-date">${e.hash} · ${e.date}</div>\n                 </div>`;\n      });\n    }\n    html += \'</div>\';\n    document.getElementById(\'restore-detail\').innerHTML = html;\n    lucide.createIcons();\n    document.getElementById(\'restore-detail\').scrollIntoView({ behavior: \'smooth\', block: \'start\' });\n  });\n}\n\nfunction restoreFileDiff(relpath, hash) {\n  restoreNavPush();\n  fetch(\'/api/restore/commit_files?hash=\' + hash).then(r => r.json()).then(cf => {\n    const others = (cf.changed_files || []).filter(f => f !== relpath);\n    fetch(\'/api/restore/diff?hash=\' + hash + \'&relpath=\' + encodeURIComponent(relpath)).then(r => r.json()).then(d => {\n      let html = renderDiffPanel(d, relpath);\n      if (others.length) {\n        html += `<div class="diff-warn"><i data-lucide="alert-triangle"></i> Commit ini juga mengubah ${others.length} file lain: ${others.slice(0, 5).map(escapeHtml).join(\', \')}${others.length > 5 ? \'…\' : \'\'}. Memulihkan cuma file ini bisa bikin kode gak konsisten.</div>`;\n      }\n      html += `<div class="patch-actions" style="margin-top:12px">\n                 <button class="btn btn-primary" style="flex:1;justify-content:center" onclick="restoreApplyFile(\'${relpath}\',\'${hash}\')"><i data-lucide="history"></i> Pulihkan File Ini ke ${hash}</button>\n               </div>`;\n      document.getElementById(\'restore-detail\').innerHTML += html;\n      lucide.createIcons();\n    });\n  });\n}\n\nfunction restoreApplyFile(relpath, hash) {\n  restoreConfirm(\'Pulihkan File Ini\', `Isi "${relpath}" akan ditimpa dengan versi commit ${hash}. Perubahan yang belum di-commit pada file ini akan hilang. Lanjutkan?`, () => {\n    fetch(\'/api/restore/apply_file\', { method: \'POST\', body: JSON.stringify({ relpath, hash }) })\n      .then(r => r.json()).then(d => {\n        if (!d.ok) return restoreToast(\'Gagal: \' + d.error, false);\n        restoreToast(`${relpath} dipulihkan ke ${hash}.`, true);\n        restoreShowHistory(relpath, true);\n      });\n  });\n}\n\nfunction restoreLoadCommits() {\n  fetch(\'/api/restore/commits\').then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat commit\', false);\n    restoreCommitsAll = d.entries || [];\n    restoreCommitsPage = 1;\n    document.getElementById(\'restore-detail\').innerHTML = \'\';\n    renderRestoreCommitsPage();\n  });\n}\n\nfunction renderRestoreCommitsPage() {\n  const start = (restoreCommitsPage - 1) * RESTORE_PAGE_SIZE;\n  const pageItems = restoreCommitsAll.slice(start, start + RESTORE_PAGE_SIZE);\n  let html = \'\';\n  pageItems.forEach(e => {\n    let tags = \'\';\n    if (e.is_head) tags += \' <span class="branch-badge" style="padding:1px 6px">HEAD</span>\';\n    if (e.is_stale) tags += \' <span style="color:var(--warn);font-size:11px;font-weight:600">· Digantikan (amend)</span>\';\n    html += `<div class="file-row${e.is_stale ? \' stale\' : \'\'}" onclick="restoreCommitDetail(\'${e.hash}\')">\n               <div class="file-icon"><i data-lucide="${e.is_stale ? \'history\' : \'git-commit\'}"></i></div>\n               <div class="file-name">${escapeHtml(e.msg)}${tags}</div>\n               <div class="file-date">${e.hash} · ${e.date}</div>\n             </div>`;\n  });\n  document.getElementById(\'restore-list\').innerHTML = html || \'<div style="padding:20px;text-align:center;color:var(--text-muted)">Belum ada commit</div>\';\n  document.getElementById(\'restore-pagination\').innerHTML = restorePaginationHtml();\n  lucide.createIcons();\n}\n\nfunction restorePaginationHtml() {\n  const total = restoreCommitsAll.length;\n  const totalPages = Math.max(1, Math.ceil(total / RESTORE_PAGE_SIZE));\n  if (totalPages <= 1) return \'\';\n  const cur = restoreCommitsPage;\n  const pageSet = new Set([1, totalPages, cur, cur - 1, cur + 1]);\n  const nums = [...pageSet].filter(p => p >= 1 && p <= totalPages).sort((a, b) => a - b);\n  let html = \'<div class="restore-pager">\';\n  html += `<button class="restore-page-btn" ${cur === 1 ? \'disabled\' : \'\'} onclick="restoreGoToPage(${cur - 1})"><i data-lucide="chevron-left"></i></button>`;\n  let prev = 0;\n  nums.forEach(p => {\n    if (prev && p - prev > 1) html += \'<span class="restore-page-dots">…</span>\';\n    html += `<button class="restore-page-btn ${p === cur ? \'active\' : \'\'}" onclick="restoreGoToPage(${p})">${p}</button>`;\n    prev = p;\n  });\n  html += `<button class="restore-page-btn" ${cur === totalPages ? \'disabled\' : \'\'} onclick="restoreGoToPage(${cur + 1})"><i data-lucide="chevron-right"></i></button>`;\n  html += `<span class="restore-page-info">Hal ${cur}/${totalPages} · ${total} commit</span>`;\n  html += \'</div>\';\n  return html;\n}\n\nfunction restoreGoToPage(p, opts) {\n  opts = opts || {};\n  const totalPages = Math.max(1, Math.ceil(restoreCommitsAll.length / RESTORE_PAGE_SIZE));\n  const target = Math.min(Math.max(1, p), totalPages);\n  if (target === restoreCommitsPage) return;\n  if (opts.autoScroll !== false) restoreNavPush();\n  restoreCommitsPage = target;\n  document.getElementById(\'restore-detail\').innerHTML = \'\';\n  restoreAnimatePageSwap(renderRestoreCommitsPage);\n  if (opts.autoScroll !== false) {\n    document.getElementById(\'restore-list\').scrollIntoView({ behavior: \'smooth\', block: \'start\' });\n  }\n}\n\nfunction restoreCommitDetail(hash) {\n  restoreNavPush();\n  fetch(\'/api/restore/commit_files?hash=\' + hash).then(r => r.json()).then(d => {\n    if (!d.ok) return restoreToast(d.error || \'Gagal memuat commit\', false);\n    let html = `<div class="github-box" style="margin-top:12px">\n                  <div class="box-header"><span>Diubah pada commit ${hash}</span></div>`;\n    if (!d.changed_files.length) {\n      html += \'<div style="padding:20px;text-align:center;color:var(--text-muted)">Tidak ada perubahan tercatat</div>\';\n    } else {\n      d.changed_files.forEach(f => {\n        html += `<div class="file-row" onclick="restoreShowFileDiffInCommit(\'${hash}\',\'${f}\')">\n                   <div class="file-icon"><i data-lucide="file-diff"></i></div>\n                   <div class="file-name">${escapeHtml(f)}</div>\n                 </div>`;\n      });\n    }\n    html += `</div><div class="patch-actions" style="margin-top:12px">\n               <button class="btn btn-primary" style="flex:1;justify-content:center" onclick="restoreApplyCommit(\'${hash}\')"><i data-lucide="history"></i> Pulihkan ke Commit Ini</button>\n             </div><div id="restore-diff-slot"></div>`;\n    document.getElementById(\'restore-detail\').innerHTML = html;\n    lucide.createIcons();\n    document.getElementById(\'restore-detail\').scrollIntoView({ behavior: \'smooth\', block: \'start\' });\n  });\n}\n\nfunction restoreShowFileDiffInCommit(hash, relpath) {\n  restoreNavPush();\n  fetch(\'/api/restore/diff?hash=\' + hash + \'&relpath=\' + encodeURIComponent(relpath)).then(r => r.json()).then(d => {\n    document.getElementById(\'restore-diff-slot\').innerHTML = renderDiffPanel(d, relpath);\n    lucide.createIcons();\n  });\n}\n\nfunction restoreApplyCommit(hash) {\n  restoreConfirm(\'Pulihkan ke Commit Ini\', `Semua perubahan setelah commit ${hash} akan hilang dari working directory (tetap ada di git history). Lanjutkan?`, () => {\n    fetch(\'/api/restore/apply_commit\', { method: \'POST\', body: JSON.stringify({ hash }) })\n      .then(r => r.json()).then(d => {\n        if (!d.ok) return restoreToast(\'Gagal: \' + d.error, false);\n        restoreToast(`Berhasil dipulihkan ke commit ${hash}.`, true);\n        restoreLoadCommits();\n      });\n  });\n}\n\nconst DIFF_CAT_CLASS = { kw: \'diff-cat-kw\', str: \'diff-cat-str\', num: \'diff-cat-num\', cmt: \'diff-cat-cmt\', deco: \'diff-cat-deco\', func: \'diff-cat-func\', cls: \'diff-cat-cls\', blt: \'diff-cat-blt\', tag: \'diff-cat-tag\', attr: \'diff-cat-attr\', sel: \'diff-cat-sel\', prop: \'diff-cat-prop\' };\n\nfunction renderDiffPanel(d, relpath) {\n  if (!d.ok) return `<div class="diff-warn"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="diff-warn svg"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>${escapeHtml(d.error || \'Gagal memuat diff\')}</div>`;\n  if (d.is_image) return `<div class="diff-file"><div class="diff-file-header"><span class="diff-file-name">🖼 ${escapeHtml(relpath)}</span></div><div style="padding:16px;color:#8b949e">File gambar — pratinjau teks tidak berlaku.</div></div>`;\n  const diff = d.diff;\n  if (!diff || diff.empty) return `<div class="diff-file"><div class="diff-file-header"><span class="diff-file-name">${escapeHtml(relpath)}</span><span style="color:#8b949e;font-size:12px">tidak ada perubahan</span></div></div>`;\n\n  const total = diff.plus + diff.minus;\n  const plusW = total > 0 ? Math.max(5, Math.round(100 * diff.plus / total)) : 50;\n\n  let html = `<div class="diff-file">\n    <div class="diff-file-header">\n      <span class="diff-file-name">\n        <i data-lucide="file-diff" style="width:14px;flex-shrink:0"></i>\n        ${escapeHtml(diff.rel)}\n      </span>\n      <span class="diff-stat-badge">\n        <span class="diff-stat-plus">+${diff.plus}</span>\n        <span class="diff-stat-minus">-${diff.minus}</span>\n        <span class="diff-stat-bar">\n          <span class="plus" style="flex:${plusW}"></span>\n          <span class="minus" style="flex:${100 - plusW}"></span>\n        </span>\n      </span>\n    </div>\n    <div class="diff-table">`;\n\n  diff.rows.forEach(row => {\n    if (row.type === \'sep\') {\n      const skipTxt = row.skip > 0 ? `@@ -${row.skip} baris tidak berubah @@` : \'@@ ... @@\';\n      html += `<div class="diff-sep">\n        <span class="diff-sep-gutter">⋯</span>\n        <span class="diff-sep-sym"> </span>\n        <span class="diff-sep-body">${skipTxt}</span>\n      </div>`;\n      return;\n    }\n\n    const kind = row.kind || \'ctx\';\n    const sym  = kind === \'add\' ? \'+\' : kind === \'del\' ? \'−\' : \' \';\n    const oldNo = (kind === \'del\' || kind === \'ctx\') ? (row.old_no || \'\') : \'\';\n    const newNo = (kind === \'add\' || kind === \'ctx\') ? (row.new_no || \'\') : \'\';\n    const chgCls = kind === \'add\' ? \'diff-chg-add\' : \'diff-chg-del\';\n\n    let code = \'\';\n    (row.tokens || []).forEach(t => {\n      let cls = \'\';\n      if (t.ws) cls = \'diff-ws\';\n      else if (t.ch) cls = chgCls;\n      else if (DIFF_CAT_CLASS[t.cat]) cls = DIFF_CAT_CLASS[t.cat];\n      code += cls ? `<span class="${cls}">${escapeHtml(t.t)}</span>` : escapeHtml(t.t);\n    });\n\n    html += `<div class="diff-row ${kind}">` +\n      `<span class="diff-gutter-old">${oldNo}</span>` +\n      `<span class="diff-gutter-new">${newNo}</span>` +\n      `<span class="diff-sym">${sym}</span>` +\n      `<span class="diff-code">${code || \' \'}</span>` +\n      `</div>`;\n  });\n\n  html += \'</div></div>\';\n  return html;\n}\n\n// ── Tab switcher helpers ──\nfunction setLogTab(active) {\n  document.getElementById(\'tab-editor\').classList.toggle(\'active\', !active);\n  document.getElementById(\'tab-log\').classList.toggle(\'active\',  active);\n}\nfunction setRunDot(show) {\n  document.getElementById(\'tab-run-dot\').classList.toggle(\'show\', show);\n  const pill = document.getElementById(\'log-running-pill\');\n  if (pill) pill.classList.toggle(\'show\', show);\n}\n\n// ── Log Panel — inline, sepanel dgn Edit (auto-lebar + swap animasi GSAP) ──\nconst _logOv = document.getElementById(\'log-fullscreen\');\nconst _logActionsRow = document.getElementById(\'log-actions-row\');\nconst _patchContainerEl = document.querySelector(\'.patch-container\');\nconst _editorWrapEl = document.querySelector(\'.patch-editor-wrap\');\nconst _editorActionsEl = document.getElementById(\'patch-editor-actions\');\n\nfunction openLogFullscreen() {\n  if (_logOv.classList.contains(\'open\')) return;\n  _patchContainerEl.classList.add(\'log-active\');\n  setLogTab(true);\n  gsap.to([_editorWrapEl, _editorActionsEl], {\n    opacity: 0, y: -8, duration: 0.18, ease: \'power2.in\',\n    onComplete() {\n      _editorWrapEl.style.display = \'none\';\n      _editorActionsEl.style.display = \'none\';\n      _logOv.classList.add(\'open\');\n      _logActionsRow.classList.add(\'open\');\n      lucide.createIcons();\n      gsap.fromTo([_logOv, _logActionsRow],\n        { opacity: 0, y: 14 },\n        { opacity: 1, y: 0, duration: 0.42, ease: \'power3.out\', stagger: 0.05 }\n      );\n    }\n  });\n}\n\nfunction closeLogFullscreen() {\n  if (!_logOv.classList.contains(\'open\')) return;\n  gsap.to([_logOv, _logActionsRow], {\n    opacity: 0, y: 10, duration: 0.18, ease: \'power2.in\',\n    onComplete() {\n      _logOv.classList.remove(\'open\');\n      _logActionsRow.classList.remove(\'open\');\n      gsap.set([_logOv, _logActionsRow], { clearProps: \'all\' });\n      _patchContainerEl.classList.remove(\'log-active\');\n      _editorWrapEl.style.display = \'\';\n      _editorActionsEl.style.display = \'\';\n      gsap.fromTo([_editorWrapEl, _editorActionsEl],\n        { opacity: 0, y: -10 },\n        { opacity: 1, y: 0, duration: 0.4, ease: \'power3.out\', stagger: 0.04 }\n      );\n      setLogTab(false);\n      setRunDot(false);\n    }\n  });\n}\n\n// Tab click — Edit\ndocument.getElementById(\'tab-editor\').onclick = () => {\n  if (_logOv.classList.contains(\'open\')) closeLogFullscreen();\n};\n// Tab click — Log\ndocument.getElementById(\'tab-log\').onclick = () => {\n  if (!_logOv.classList.contains(\'open\')) openLogFullscreen();\n};\n\ndocument.addEventListener(\'keydown\', e => {\n  if (e.key === \'Escape\' && _logOv.classList.contains(\'open\')) closeLogFullscreen();\n});\n\n// ── Log zoom — pinch dua jari langsung di panel log (bukan tombol) ──\nlet _logScale = 0.85;\nfunction setLogZoom(z) {\n  _logScale = Math.max(0.7, Math.min(2.0, z));\n  document.documentElement.style.setProperty(\'--log-scale\', _logScale.toFixed(2));\n}\nconst _logZoomIndicator = document.getElementById(\'log-zoom-indicator\');\nlet _zoomIndicatorTimer = null;\nfunction _flashZoomIndicator() {\n  if (!_logZoomIndicator) return;\n  _logZoomIndicator.textContent = Math.round(_logScale * 100) + \'%\';\n  _logZoomIndicator.classList.add(\'show\');\n  clearTimeout(_zoomIndicatorTimer);\n  _zoomIndicatorTimer = setTimeout(() => _logZoomIndicator.classList.remove(\'show\'), 500);\n}\nfunction _pinchDist(touches) {\n  const dx = touches[0].clientX - touches[1].clientX;\n  const dy = touches[0].clientY - touches[1].clientY;\n  return Math.hypot(dx, dy);\n}\nlet _pinchStartDist = null;\nlet _pinchStartScale = 1;\n_logOv.addEventListener(\'touchstart\', (e) => {\n  if (e.touches.length === 2) {\n    _pinchStartDist = _pinchDist(e.touches);\n    _pinchStartScale = _logScale;\n  }\n}, { passive: true });\n_logOv.addEventListener(\'touchmove\', (e) => {\n  if (e.touches.length === 2 && _pinchStartDist) {\n    e.preventDefault();\n    const factor = _pinchDist(e.touches) / _pinchStartDist;\n    setLogZoom(_pinchStartScale * factor);\n    _flashZoomIndicator();\n  }\n}, { passive: false });\nconst _endPinch = () => { _pinchStartDist = null; };\n_logOv.addEventListener(\'touchend\', _endPinch);\n_logOv.addEventListener(\'touchcancel\', _endPinch);\n\n// ── Autoscroll toggle button ──\nconst _autoscrollBtn = document.getElementById(\'btn-autoscroll-toggle\');\n_autoscrollBtn.onclick = () => {\n  const cb = document.getElementById(\'chk-autoscroll\');\n  cb.checked = !cb.checked;\n  _autoscrollBtn.classList.toggle(\'on\', cb.checked);\n};\n\n// ── Diff preview zoom — pinch dua jari langsung di panel diff (bukan tombol) ──\nlet _diffZoom = 1.0;\nfunction setDiffZoom(z) {\n  _diffZoom = Math.max(0.65, Math.min(1.8, z));\n  document.documentElement.style.setProperty(\'--diff-zoom\', _diffZoom.toFixed(2));\n}\nconst _diffZoomIndicator = document.getElementById(\'diff-zoom-indicator\');\nlet _diffZoomIndicatorTimer = null;\nfunction _flashDiffZoomIndicator() {\n  if (!_diffZoomIndicator) return;\n  _diffZoomIndicator.textContent = Math.round(_diffZoom * 100) + \'%\';\n  _diffZoomIndicator.classList.add(\'show\');\n  clearTimeout(_diffZoomIndicatorTimer);\n  _diffZoomIndicatorTimer = setTimeout(() => _diffZoomIndicator.classList.remove(\'show\'), 500);\n}\nconst _viewRestoreEl = document.getElementById(\'view-restore\');\nlet _diffPinchStartDist = null;\nlet _diffPinchStartZoom = 1;\n_viewRestoreEl.addEventListener(\'touchstart\', (e) => {\n  if (e.touches.length === 2 && e.target.closest(\'.diff-table\')) {\n    _diffPinchStartDist = _pinchDist(e.touches);\n    _diffPinchStartZoom = _diffZoom;\n  }\n}, { passive: true });\n_viewRestoreEl.addEventListener(\'touchmove\', (e) => {\n  if (e.touches.length === 2 && _diffPinchStartDist) {\n    e.preventDefault();\n    const factor = _pinchDist(e.touches) / _diffPinchStartDist;\n    setDiffZoom(_diffPinchStartZoom * factor);\n    _flashDiffZoomIndicator();\n  }\n}, { passive: false });\nconst _endDiffPinch = () => { _diffPinchStartDist = null; };\n_viewRestoreEl.addEventListener(\'touchend\', _endDiffPinch);\n_viewRestoreEl.addEventListener(\'touchcancel\', _endDiffPinch);\n\n// Execute Job Engine\nfunction startStream(jobId) {\n  currentJobId = jobId;\n  setStatus(\'running\', \'Berjalan...\');\n  setRunDot(true);\n  openLogFullscreen();\n  \n  const es = new EventSource(\'/api/stream/\' + jobId);\n  es.onmessage = (ev) => {\n    const item = JSON.parse(ev.data);\n    if (item.type === \'output\') appendLog(item.text);\n    else if (item.type === \'prompt\') {\n      // \'anykey\' tanpa opsi/isi kompleks -> kartu inline di log (bukan modal).\n      // Kind lain (confirm/text/patch) masih pakai sheet modal karena butuh\n      // ruang lebih (opsi banyak, textarea, dsb).\n      if (item.kind === \'anykey\') appendInlinePrompt(item);\n      else openSheet(item);\n    }\n    else if (item.type === \'error\') {\n      const errEl = document.createElement(\'div\'); errEl.className = \'log-error-block\';\n      errEl.textContent = \'⚠ \' + item.text; logEl.appendChild(errEl);\n      setStatus(\'error\', \'Error\');\n    }\n    else if (item.type === \'done\') {\n      setStatus(\'done\', \'Selesai\');\n      btnApply.disabled = false; btnDryRun.disabled = false;\n      setRunDot(false);\n      closeSheet(); es.close(); loadRepo(currentRepoPath);\n    }\n  };\n  es.onerror = () => {\n    setStatus(\'error\', \'Terputus\'); btnApply.disabled = false; btnDryRun.disabled = false; es.close();\n  };\n}\n\nfunction runFeature(featureId) {\n  logEl.innerHTML = \'\'; term.rows = []; term.cur = 0;\n  setStatus(\'running\', \'Menjalankan...\');\n  fetch(\'/api/run_feature\', {\n    method: \'POST\', body: JSON.stringify({feature: featureId})\n  }).then(r=>r.json()).then(d => {\n    if(d.ok) startStream(d.job_id);\n    else alert(\'Gagal: \' + d.error);\n  });\n}\n\n// action-btn sudah dikonversi ke native view — binding lama dihapus\nfunction execPatch(isDryRun) {\n  btnApply.disabled = true; btnDryRun.disabled = true;\n  logEl.innerHTML = \'\'; term.rows = []; term.cur = 0;\n  \n  fetch(\'/api/apply\', {\n    method: \'POST\', body: JSON.stringify({patch_text: patchEl.value, folder: folderEl.value, dry_run: isDryRun})\n  }).then(r=>r.json()).then(d => {\n    if(!d.ok) { alert(d.error); btnApply.disabled=false; btnDryRun.disabled=false; return; }\n    startStream(d.job_id);\n  });\n}\nbtnApply.onclick = () => execPatch(false);\nbtnDryRun.onclick = () => execPatch(true);\ndocument.getElementById(\'btn-clear-patch\').onclick = () => { patchEl.value=\'\'; patchEl.focus(); };\ndocument.getElementById(\'btn-clear-log\').onclick = () => { logEl.innerHTML=\'\'; term.rows=[]; term.cur=0; };\ndocument.getElementById(\'btn-copy-log\').onclick = () => {\n  const txt = logEl.innerText || logEl.textContent || \'\';\n  const fallback = () => {\n    const ta = document.createElement(\'textarea\'); ta.value = txt;\n    ta.style.cssText = \'position:fixed;opacity:0\'; document.body.appendChild(ta);\n    ta.select(); try { document.execCommand(\'copy\'); } catch(e) {}\n    document.body.removeChild(ta);\n  };\n  if (navigator.clipboard && navigator.clipboard.writeText) navigator.clipboard.writeText(txt).catch(fallback);\n  else fallback();\n};\n\n// Inline Prompt Card (kind \'anykey\') — menyatu di alur log, user klik baru lanjut\nfunction appendInlinePrompt(item) {\n  const card = document.createElement(\'div\');\n  card.className = \'inline-prompt-card\';\n  card.innerHTML = `\n    <div class="inline-prompt-icon"><i data-lucide="circle-help"></i></div>\n    <div class="inline-prompt-text">${escapeHtml(item.message || \'Proses menunggu konfirmasi Anda untuk lanjut.\')}</div>\n    <button class="btn btn-primary inline-prompt-btn">Lanjutkan</button>\n  `;\n  logEl.appendChild(card);\n  lucide.createIcons();\n  if (document.getElementById(\'chk-autoscroll\').checked) logEl.scrollTop = logEl.scrollHeight;\n\n  card.querySelector(\'.inline-prompt-btn\').onclick = () => {\n    card.classList.add(\'answered\');\n    card.querySelector(\'.inline-prompt-icon\').innerHTML = \'<i data-lucide="check-circle-2"></i>\';\n    const btn = card.querySelector(\'.inline-prompt-btn\');\n    btn.disabled = true; btn.textContent = \'Dilanjutkan\';\n    lucide.createIcons();\n    fetch(\'/api/answer/\' + currentJobId, {\n      method: \'POST\', body: JSON.stringify({value: \'ENTER\'})\n    });\n  };\n}\n\n// Sheet Modals for Prompts\nfunction openSheet(item) {\n  sheetTitleTextEl.textContent = item.kind === \'confirm\' ? item.title : \'Input Dibutuhkan\';\n  let html = \'\';\n  if(item.message) {\n    if(Array.isArray(item.message)) item.message.forEach(m => html += `<p>${escapeHtml(m)}</p>`);\n    else html += `<p>${escapeHtml(item.message)}</p>`;\n  }\n  \n  if (item.kind === \'confirm\') {\n    html += \'<div class="sheet-opts">\';\n    item.options.forEach((o, i) => {\n      let cls = i===0 ? \'btn-primary\' : \'\';\n      html += `<button class="btn ${cls}" data-val="${escapeHtml(o.key)}">${escapeHtml(o.label)}</button>`;\n    });\n    html += \'</div>\';\n  } else if (item.kind === \'anykey\') {\n    html += \'<div class="sheet-opts"><button class="btn btn-primary" id="sheet-anykey-btn">Lanjutkan</button></div>\';\n  } else if (item.kind === \'patch\') {\n    html += `<textarea id="sheet-patch-input" placeholder="Tempel patch berikutnya..."></textarea>\n             <div class="sheet-opts">\n               <button class="btn btn-primary" id="sheet-patch-send">Terapkan</button>\n               <button class="btn" id="sheet-patch-cancel">Selesai (Batal)</button>\n             </div>`;\n  } else {\n    html += `<input type="text" id="sheet-text-input">\n             <div class="sheet-opts"><button class="btn btn-primary" id="sheet-text-send">Kirim</button></div>`;\n  }\n  \n  sheetBodyEl.innerHTML = html;\n  sheetEl.classList.add(\'open\');\n  gsap.fromTo("#modal", {y: 50, opacity: 0}, {y: 0, opacity: 1, duration: 0.3, ease: "power2.out"});\n  \n  if(item.kind === \'confirm\') {\n    sheetBodyEl.querySelectorAll(\'button[data-val]\').forEach(b => {\n      b.onclick = () => answerSheet(b.getAttribute(\'data-val\'));\n    });\n  } else if (item.kind === \'anykey\') {\n    document.getElementById(\'sheet-anykey-btn\').onclick = () => answerSheet(\'ENTER\');\n  } else if (item.kind === \'patch\') {\n    document.getElementById(\'sheet-patch-send\').onclick = () => answerSheet(document.getElementById(\'sheet-patch-input\').value);\n    document.getElementById(\'sheet-patch-cancel\').onclick = () => answerSheet(\'\');\n  } else {\n    const inp = document.getElementById(\'sheet-text-input\');\n    inp.focus();\n    document.getElementById(\'sheet-text-send\').onclick = () => answerSheet(inp.value);\n    inp.onkeydown = (e) => { if(e.key === \'Enter\') answerSheet(inp.value); };\n  }\n}\n\nfunction closeSheet() { sheetEl.classList.remove(\'open\'); }\nfunction answerSheet(val) {\n  closeSheet();\n  fetch(\'/api/answer/\' + currentJobId, {\n    method: \'POST\', body: JSON.stringify({value: val})\n  });\n}\n\n// ===== HELPER NOTIF =====\nfunction showMsg(elId, ok, text, ms) {\n  ms = ms || 3500;\n  const el = document.getElementById(elId);\n  if (!el) return;\n  el.style.display    = \'block\';\n  el.style.background = ok ? \'rgba(46,125,79,0.12)\'  : \'rgba(192,57,43,0.10)\';\n  el.style.border     = ok ? \'1px solid var(--ok)\'   : \'1px solid var(--err)\';\n  el.style.color      = ok ? \'var(--ok)\'             : \'var(--err)\';\n  el.textContent = text;\n  clearTimeout(el._t);\n  el._t = setTimeout(function(){ el.style.display = \'none\'; }, ms);\n}\n\n// ===== THRESHOLD =====\nfunction thrLoad() {\n  fetch(\'/api/threshold\').then(function(r){ return r.json(); }).then(function(d) {\n    if (!d.ok) return;\n    document.getElementById(\'thr-tolerance\').value = d.tolerance;\n    document.getElementById(\'thr-max-gap\').value   = d.max_gap;\n    document.getElementById(\'thr-partial\').value   = d.partial_min_score;\n  });\n}\ndocument.getElementById(\'btn-thr-save\').onclick = function() {\n  var body = {\n    tolerance:         parseInt(document.getElementById(\'thr-tolerance\').value,  10),\n    max_gap:           parseInt(document.getElementById(\'thr-max-gap\').value,    10),\n    partial_min_score: parseFloat(document.getElementById(\'thr-partial\').value),\n  };\n  fetch(\'/api/threshold\', { method: \'POST\', body: JSON.stringify(body) })\n    .then(function(r){ return r.json(); })\n    .then(function(d){ showMsg(\'thr-msg\', d.ok, d.ok ? \'✓ Threshold berhasil disimpan.\' : \'✗ \' + (d.error || \'Gagal.\')); });\n};\n\n// ===== IDENTITAS GIT =====\nfunction gitIdLoad() {\n  fetch(\'/api/git_identity\').then(function(r){ return r.json(); }).then(function(d) {\n    if (!d.ok) return;\n    document.getElementById(\'git-name\').value  = d.name;\n    document.getElementById(\'git-email\').value = d.email;\n  });\n}\ndocument.getElementById(\'btn-git-save\').onclick = function() {\n  var body = {\n    name:  document.getElementById(\'git-name\').value,\n    email: document.getElementById(\'git-email\').value,\n  };\n  fetch(\'/api/git_identity\', { method: \'POST\', body: JSON.stringify(body) })\n    .then(function(r){ return r.json(); })\n    .then(function(d){\n      showMsg(\'git-id-msg\', d.ok,\n        d.ok ? (\'✓ Identitas disimpan — \' + d.name + \' <\' + d.email + \'>\') : (\'✗ \' + (d.error || \'Gagal.\')));\n    });\n};\n\n// ===== UBAH DIREKTORI =====\nfunction dirLoad() {\n  fetch(\'/api/dir\').then(function(r){ return r.json(); }).then(function(d) {\n    if (!d.ok) return;\n    document.getElementById(\'dir-current\').textContent = d.current;\n    var listEl = document.getElementById(\'dir-recent-list\');\n    if (!d.recent.length) {\n      listEl.innerHTML = \'<div style="padding:16px;color:var(--text-muted);font-size:14px;">Belum ada riwayat direktori lain.</div>\';\n      return;\n    }\n    var html = \'\';\n    d.recent.forEach(function(p) {\n      var safe = escapeHtml(p).replace(/\'/g, \'&#39;\');\n      html += \'<div class="file-row" onclick="dirApply(\\\'\' + safe + \'\\\')">\'\n            + \'<div class="file-icon folder"><i data-lucide="folder"></i></div>\'\n            + \'<div class="file-name" style="font-family:monospace;font-size:13px;">\' + escapeHtml(p) + \'</div>\'\n            + \'</div>\';\n    });\n    listEl.innerHTML = html;\n    lucide.createIcons();\n  });\n}\nfunction dirApply(path) {\n  fetch(\'/api/dir\', { method: \'POST\', body: JSON.stringify({ path: path }) })\n    .then(function(r){ return r.json(); })\n    .then(function(d) {\n      showMsg(\'dir-msg\', d.ok, d.ok ? \'✓ Direktori diubah ke: \' + d.path : \'✗ \' + (d.error || \'Gagal.\'));\n      if (d.ok) { dirLoad(); loadRepo(); }\n    });\n}\ndocument.getElementById(\'btn-dir-refresh\').onclick  = function(){ dirLoad(); };\ndocument.getElementById(\'dir-apply-new\').onclick     = function() {\n  var path = document.getElementById(\'dir-new-path\').value.trim();\n  if (!path) return;\n  dirApply(path);\n  document.getElementById(\'dir-new-path\').value = \'\';\n};\ndocument.getElementById(\'dir-new-path\').onkeydown = function(e) {\n  if (e.key === \'Enter\') document.getElementById(\'dir-apply-new\').click();\n};\n\n// ===== CARI & GANTI MANUAL =====\ndocument.getElementById(\'cgm-run\').onclick = function(){ execCGM(false); };\ndocument.getElementById(\'cgm-dry\').onclick = function(){ execCGM(true);  };\nfunction execCGM(isDryRun) {\n  var find    = document.getElementById(\'cgm-find\').value;\n  var replace = document.getElementById(\'cgm-replace\').value;\n  var file    = document.getElementById(\'cgm-file\').value.trim();\n  if (!find.trim()) { alert(\'Teks pencarian tidak boleh kosong!\'); return; }\n  logEl.innerHTML = \'\'; term.rows = []; term.cur = 0;\n  fetch(\'/api/search_replace\', {\n    method: \'POST\',\n    body: JSON.stringify({ find_text: find, replace_text: replace, file_hint: file, dry_run: isDryRun })\n  }).then(function(r){ return r.json(); }).then(function(d) {\n    if (!d.ok) { alert(\'Gagal: \' + d.error); return; }\n    startStream(d.job_id);\n  });\n}\n\n// ===== SETUP AI =====\nvar aiSetupState = { provider: \'groq\', model: \'\', keys: [] };\n\nfunction aiSetupLoad() {\n  fetch(\'/api/ai_config\').then(function(r){ return r.json(); }).then(function(d) {\n    if (!d.ok) return;\n    aiSetupState.provider = d.provider;\n    aiSetupState.model    = d.model;\n    aiSetupState.keys     = d.keys_masked;\n    aiRenderStatus(d);\n    aiRenderProviders(d.providers, d.provider);\n    aiLoadModels(d.provider, d.model);\n    aiRenderKeys(d.keys_masked);\n    document.getElementById(\'ai-key-hint\').textContent = d.key_hint;\n  });\n}\n\nfunction aiRenderStatus(d) {\n  var el = document.getElementById(\'ai-status-badge\');\n  var on = d.key_count > 0;\n  el.textContent        = on ? (\'ON — \' + d.provider + \' / \' + (d.model || \'-\')) : \'OFF — Belum setup\';\n  el.style.background   = on ? \'rgba(46,125,79,0.15)\'  : \'rgba(192,57,43,0.10)\';\n  el.style.color        = on ? \'var(--ok)\'  : \'var(--err)\';\n  el.style.borderColor  = on ? \'var(--ok)\'  : \'var(--err)\';\n}\n\nfunction aiRenderProviders(providers, current) {\n  var html = \'\';\n  (providers || []).forEach(function(p) {\n    var active = (p.id === current);\n    html += \'<div class="file-row" onclick="aiSelectProvider(\\\'\' + p.id + \'\\\')"\'\n          + (active ? \' style="background:rgba(217,119,87,0.1);"\' : \'\') + \'>\'\n          + \'<div class="file-icon"><i data-lucide="\' + (active ? \'check-circle-2\' : \'circle\') + \'"></i></div>\'\n          + \'<div class="file-name"><strong>\' + escapeHtml(p.label) + \'</strong> \'\n          + \'<span style="color:var(--text-muted);font-size:13px;">\' + escapeHtml(p.desc) + \'</span></div>\'\n          + \'</div>\';\n  });\n  document.getElementById(\'ai-provider-list\').innerHTML = html;\n  lucide.createIcons();\n}\n\nfunction aiSelectProvider(prov) {\n  fetch(\'/api/ai_config\', { method: \'POST\', body: JSON.stringify({ provider: prov }) })\n    .then(function(r){ return r.json(); })\n    .then(function(d) {\n      if (!d.ok) return;\n      aiSetupState.provider = prov;\n      aiRenderStatus(d);\n      aiRenderProviders(d.providers, prov);\n      aiLoadModels(prov, d.model);\n      aiRenderKeys(d.keys_masked);\n      document.getElementById(\'ai-key-hint\').textContent = d.key_hint;\n    });\n}\n\nfunction aiLoadModels(prov, currentModel) {\n  var el = document.getElementById(\'ai-model-list\');\n  el.innerHTML = \'<div style="padding:12px 16px;color:var(--text-muted);font-size:13px;">Memuat model...</div>\';\n  fetch(\'/api/ai_config/models?provider=\' + encodeURIComponent(prov))\n    .then(function(r){ return r.json(); })\n    .then(function(d) {\n      var html = \'\';\n      (d.models || []).forEach(function(m) {\n        var active  = (m.id === currentModel);\n        var safeId  = escapeHtml(m.id).replace(/\'/g, \'&#39;\');\n        html += \'<div class="file-row" onclick="aiSelectModel(\\\'\' + safeId + \'\\\')"\'\n              + (active ? \' style="background:rgba(217,119,87,0.1);"\' : \'\') + \'>\'\n              + \'<div class="file-icon"><i data-lucide="\' + (active ? \'check-circle-2\' : \'circle\') + \'"></i></div>\'\n              + \'<div class="file-name" style="font-family:monospace;font-size:13px;">\' + escapeHtml(m.id) + \'</div>\'\n              + \'<div class="file-date">\' + escapeHtml(m.desc || \'\') + \'</div>\'\n              + \'</div>\';\n      });\n      if (!d.models || !d.models.length) {\n        html = \'<div style="padding:12px 16px;color:var(--text-muted);font-size:13px;">Belum ada data model — coba klik Sync.</div>\';\n      }\n      el.innerHTML = html;\n      if (d.models && d.models.length && !d.synced) {\n        el.innerHTML += \'<div style="padding:2px 16px 8px;font-size:12px;color:var(--text-muted);">Daftar statis — klik Sync untuk memuat dari API.</div>\';\n      }\n      lucide.createIcons();\n    });\n}\n\nfunction aiSelectModel(modelId) {\n  fetch(\'/api/ai_config\', { method: \'POST\', body: JSON.stringify({ model: modelId }) })\n    .then(function(r){ return r.json(); })\n    .then(function(d) {\n      if (!d.ok) return;\n      aiSetupState.model = modelId;\n      aiRenderStatus(d);\n      aiLoadModels(aiSetupState.provider, modelId);\n    });\n}\n\ndocument.getElementById(\'btn-ai-sync-models\').onclick = function() {\n  var btn = document.getElementById(\'btn-ai-sync-models\');\n  btn.disabled = true;\n  fetch(\'/api/ai_config/models?provider=\' + encodeURIComponent(aiSetupState.provider))\n    .then(function(r){ return r.json(); })\n    .then(function() {\n      btn.disabled = false;\n      aiLoadModels(aiSetupState.provider, aiSetupState.model);\n    });\n};\n\ndocument.getElementById(\'btn-ai-model-manual\').onclick = function() {\n  var val = document.getElementById(\'ai-model-manual\').value.trim();\n  if (!val) return;\n  aiSelectModel(val);\n  document.getElementById(\'ai-model-manual\').value = \'\';\n};\n\nfunction aiRenderKeys(keysMasked) {\n  var el = document.getElementById(\'ai-key-list\');\n  if (!keysMasked || !keysMasked.length) {\n    el.innerHTML = \'<div style="padding:12px 16px;color:var(--text-muted);font-size:13px;">Belum ada API Key tersimpan.</div>\';\n    return;\n  }\n  var html = \'\';\n  keysMasked.forEach(function(k, i) {\n    html += \'<div class="file-row">\'\n          + \'<div class="file-icon"><i data-lucide="key"></i></div>\'\n          + \'<div class="file-name" style="font-family:monospace;font-size:13px;">\' + escapeHtml(k) + \'</div>\'\n          + \'<button class="ghost-btn" onclick="aiRemoveKey(\' + i + \')" title="Hapus key ini" style="color:var(--err)"><i data-lucide="trash-2"></i></button>\'\n          + \'</div>\';\n  });\n  el.innerHTML = html;\n  lucide.createIcons();\n}\n\ndocument.getElementById(\'btn-ai-key-add\').onclick = function() {\n  var val = document.getElementById(\'ai-key-new\').value.trim();\n  if (!val) return;\n  fetch(\'/api/ai_config\', { method: \'POST\', body: JSON.stringify({ api_key_add: val, provider: aiSetupState.provider }) })\n    .then(function(r){ return r.json(); })\n    .then(function(d) {\n      if (!d.ok) return;\n      document.getElementById(\'ai-key-new\').value = \'\';\n      aiSetupLoad();\n    });\n};\ndocument.getElementById(\'ai-key-new\').onkeydown = function(e) {\n  if (e.key === \'Enter\') document.getElementById(\'btn-ai-key-add\').click();\n};\n\nfunction aiRemoveKey(idx) {\n  fetch(\'/api/ai_config\', { method: \'POST\', body: JSON.stringify({ api_key_remove: idx, provider: aiSetupState.provider }) })\n    .then(function(r){ return r.json(); })\n    .then(function(d) { if (d.ok) aiSetupLoad(); });\n}\n\ndocument.getElementById(\'btn-ai-test-key\').onclick = function() {\n  var res = document.getElementById(\'ai-test-result\');\n  res.textContent = \'Menguji koneksi...\';\n  fetch(\'/api/ai_config/test\', { method: \'POST\', body: JSON.stringify({ provider: aiSetupState.provider }) })\n    .then(function(r){ return r.json(); })\n    .then(function(d) {\n      if (!d.ok) { res.style.color = \'var(--err)\'; res.textContent = d.error; return; }\n      res.innerHTML = d.results.map(function(r) {\n        return \'<div style="color:\' + (r.valid ? \'var(--ok)\' : \'var(--err)\') + \'">\'\n             + (r.valid ? \'✓\' : \'✗\') + \' \' + escapeHtml(r.key)\n             + (r.error ? \' — \' + escapeHtml(r.error) : \'\')\n             + \'</div>\';\n      }).join(\'\');\n    });\n};\n</script>\n<script>\nif (\'serviceWorker\' in navigator) {\n  window.addEventListener(\'load\', function() {\n    navigator.serviceWorker.register(\'/sw.js\').then(function(reg) {\n      console.log(\'SW terdaftar, scope:\', reg.scope);\n    }).catch(function(err) {\n      console.log(\'SW register gagal:\', err);\n    });\n  });\n}\n</script>\n</body>\n</html>\n'
def main():print(f"[FR Tool Web] Folder aktif: {frtool.SOURCE_ROOT}");print('[FR Tool Web] Menjalankan init & auth (sama seperti CLI)...');frtool._init_blk();frtool._sys_auth();frtool.load_thresholds();frtool.load_frignore();frtool.load_git_identity();install_web_io();print('[FR Tool Web] Siap. Buka di browser HP yang sama:');print(f"  http://127.0.0.1:{PORT}");app.run(host='127.0.0.1',port=PORT,threaded=True,debug=False,use_reloader=False)
if __name__=='__main__':main()